        "promptContent": "{\n  \"type\": \"学术论文方法 Pipeline 总览图（method overview figure）\",\n  \"goal\": \"生成一张可直接放进顶会论文或 SIGGRAPH 附件的 diffusion training pipeline 总览图，白底、几何精确、可单色印刷\",\n  \"canvas\": {\n    \"aspect_ratio\": \"2:1\",\n    \"background\": \"pure white #FFFFFF\",\n    \"outer_padding\": \"60px around the diagram\",\n    \"render_quality\": \"vector-clean look, anti-aliased edges, sharp text\"\n  },\n  \"title_caption\": {\n    \"figure_label\": \"Figure 2.\",\n    \"caption\": \"Training-time pipeline of our text-conditioned latent diffusion model (LDM).\",\n    \"position\": \"bottom-center, smaller sans-serif\"\n  },\n  \"input\": {\n    \"label\": \"Image–Text Pairs (x, c)\",\n    \"thumbnail\": \"a photo patch icon plus a one-line text caption block\",\n    \"position\": \"leftmost, vertically centered\"\n  },\n  \"stages\": {\n    \"count\": \"4\",\n    \"items\": [\n      {\n        \"id\": \"S1\",\n        \"name\": \"VAE Encode\",\n        \"icon_or_glyph\": \"a small encoder arrow mapping RGB tile to 4× downsampled latent grid\",\n        \"sub_label\": \"f8 downsampling, z ∈ ℝ^{4×(H/8)×(W/8)}\"\n      },\n      {\n        \"id\": \"S2\",\n        \"name\": \"Noise & Timestep\",\n        \"icon_or_glyph\": \"a latent tensor with random noise overlay and a clock glyph for t\",\n        \"sub_label\": \"DDPM, t ~ U(0, T)\"\n      },\n      {\n        \"id\": \"S3\",\n        \"name\": \"U-Net ϵ_θ (Text-Cond.)\",\n        \"icon_or_glyph\": \"U-shaped stack with a side branch for CLIP / T5 text tokens\",\n        \"sub_label\": \"cross-attn, predict noise ε\"\n      },\n      {\n        \"id\": \"S4\",\n        \"name\": \"Decoder & VAE\",\n        \"icon_or_glyph\": \"MSE or v-prediction loss symbol pointing from prediction to target noise, next to a tiny decoder icon\",\n        \"sub_label\": \"L_simple + optional L_lpips (aux.)\"\n      }\n    ]\n  },\n  \"output\": {\n    \"label\": \"Trained Weights θ\",\n    \"thumbnail\": \"a small disk or checkpoint symbol with a '.ckpt' style label\",\n    \"position\": \"rightmost, vertically centered\"\n  },\n  \"stage_block_style\": {\n    \"shape\": \"rounded rectangle (corner radius ~6px)\",\n    \"size_per_stage\": \"around 120px wide × 80px tall, all stages identical size\",\n    \"fill\": \"very light #F1F5F9 for S1–S2, #ECFDF5 for S3, #FEF3C7 for S4 (grouping encode / denoise / loss)\",\n    \"border\": \"1.2px solid #334155\",\n    \"title_text\": \"stage name in bold sans-serif, 11-12pt\",\n    \"icon_position\": \"centered inside block\",\n    \"sub_label_text\": \"italic gray sub-labels\"\n  },\n  \"connectors\": {\n    \"style\": \"thin black arrows (1.2px)\",\n    \"rule\": \"left to right; optional tiny label on arrow: 'z_t' between S2 and S3\",\n    \"skip_connections\": {\n      \"enabled\": \"true\",\n      \"rule\": \"dashed skip from S1 latent representation arching to S3 input side, labeled 'skip connection' / 'residual on latent' if space allows\"\n    }\n  },\n  \"extras\": {\n    \"loss_branch\": {\n      \"enabled\": \"true\",\n      \"label\": \"L = ||ε − ε_θ(z_t, t, c)||_2^2\",\n      \"rule\": \"small dashed line from S3 output to a 'Loss' box above the main arrow, formula in italic\"\n    },\n    \"color_legend\": {\n      \"enabled\": \"true\",\n      \"rule\": \"bottom-right: three swatches for encode / denoise / objective groups\"\n    }\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"all stage blocks identical size and vertically aligned\",\n      \"white background, no photo textures\",\n      \"English terminology for all stage titles and sub_labels\",\n      \"grayscale-friendly contrast\",\n      \"arrows and loss branch do not occlude main labels\"\n    ],\n    \"avoid\": [\n      \"3D glass cards, stock illustration style\",\n      \"emoji or brand logos\",\n      \"cluttered hyperparameter tables inside the figure\"\n    ]\n  }\n}\n",
