        "promptContent": "{\n  \"type\": \"横向 1×N 多工况对比\",\n  \"goal\": \"生成一张材料学论文 results 章节用的 1×4 横向多工况微观组织对比图，所有 panel 严格统一、白底、定性渲染，不含任何虚构尺寸数值\",\n  \"canvas\": {\n    \"aspect_ratio\": \"4:1\",\n    \"background\": \"pure white #FFFFFF\",\n    \"outer_padding\": \"40px around the row\",\n    \"inter_panel_gap\": \"16px horizontal, identical between panels\",\n    \"render_quality\": \"vector-clean look, anti-aliased, sharp text\"\n  },\n  \"title_caption\": {\n    \"figure_label\": \"Figure 5.\",\n    \"caption\": \"SEM micrographs of the Ni-based superalloy after 4 h aging at varying temperatures, showing the evolution of γ' precipitates.\",\n    \"position\": \"bottom-center, italic compact sans-serif, smaller font size\"\n  },\n  \"grid_layout\": {\n    \"rows\": \"1\",\n    \"cols\": \"4\",\n    \"panel_count\": \"4\",\n    \"rule\": \"1 × 4 == 4; all panels identical size; consistent horizontal alignment\"\n  },\n  \"panels\": {\n    \"panel_type\": \"micrograph\",\n    \"panel_type_options\": \"micrograph\",\n    \"rule\": \"ALL panels rendered as schematic SEM-style micrographs at the same magnification\",\n    \"items\": [\n      {\n        \"id\": \"(a)\",\n        \"condition_label\": \"T = 700 °C\",\n        \"condition_detail\": \"early-stage γ' nucleation\"\n      },\n      {\n        \"id\": \"(b)\",\n        \"condition_label\": \"T = 800 °C\",\n        \"condition_detail\": \"fine γ' precipitates\"\n      },\n      {\n        \"id\": \"(c)\",\n        \"condition_label\": \"T = 900 °C\",\n        \"condition_detail\": \"coarsened γ' precipitates\"\n      },\n      {\n        \"id\": \"(d)\",\n        \"condition_label\": \"T = 1000 °C\",\n        \"condition_detail\": \"rafted γ' morphology\"\n      }\n    ]\n  },\n  \"panel_style\": {\n    \"frame\": \"thin black border 1px around each panel, identical for all four\",\n    \"label_position\": \"(a) (b) (c) (d) at top-left of each panel, white-bordered black text on a tiny dark patch for legibility on dark micrograph background\",\n    \"condition_label_position\": \"centered above each panel, identical position across all four\",\n    \"axis_labels\": \"no axis labels; instead a shared horizontal scale bar at bottom-right of every panel, identical length and identical 'scale bar' notation, but with no numerical micron value (qualitative)\",\n    \"internal_titles\": \"no decorative per-panel titles; rely on (a)(b)(c)(d) + condition label only\"\n  },\n  \"shared_legend\": {\n    \"enabled\": \"false\",\n    \"position\": \"right-of-grid\",\n    \"rule\": \"no colormap legend needed for monochromatic SEM-style micrographs\",\n    \"colorbar_range\": \"qualitative-low-to-high\",\n    \"colorbar_range_rule\": \"n/a\"\n  },\n  \"color_logic\": {\n    \"rule\": \"all panels rendered in a charcoal-to-light-gray monochrome palette (#1F2937 → #94A3B8 → #E5E7EB), no other hues; same value range across panels\",\n    \"must_print_grayscale_readable\": true\n  },\n  \"data_authenticity\": {\n    \"user_provided_real_data\": \"false\",\n    \"rule_when_false\": \"render qualitative SEM-style schematics of γ' precipitates: (a) sparse small dots, (b) denser small cuboids, (c) larger cuboids with regular spacing, (d) elongated rafted plates; do NOT label any precipitate size values; do NOT include numerical scale-bar values; the impression must be of a typical SEM image, not a real dataset\",\n    \"rule_when_true\": \"n/a\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"all four panels identical size, identical aspect, identical position scheme\",\n      \"monochrome rendering, identical value range across panels\",\n      \"shared scale bar style across all panels\",\n      \"white outer background, dark micrograph interior\",\n      \"(a)(b)(c)(d) labels in identical position and identical style\",\n      \"only sans-serif typography, identical font family\",\n      \"the figure should look like SEM micrographs in Acta Materialia / Materials Characterization\"\n    ],\n    \"avoid\": [\n      \"different magnification or different brightness per panel\",\n      \"different chart type per panel, mixing micrograph with chart\",\n      \"decorative panel titles, hero panel that visually dominates\",\n      \"saturated colors, neon, vivid gradients on micrographs\",\n      \"3D rendering, lens flare, motion blur, dramatic lighting\",\n      \"fabricated numerical scale-bar values, fabricated grain-size labels, fabricated EBSD overlays\",\n      \"marketing poster aesthetics, popular-science illustration aesthetics\",\n      \"watermarks, instrument-vendor logos\"\n    ]\n  }\n}\n",
