        "promptContent": "{\n  \"type\": \"神经网络架构图（neural network architecture diagram）\",\n  \"goal\": \"生成论文级别的 encoder-only Transformer 架构图：层级清晰、tensor shape 标注、残差可辨、可灰度印刷\",\n  \"canvas\": {\n    \"aspect_ratio\": \"16:9\",\n    \"background\": \"white #FFFFFF\",\n    \"outer_padding\": \"60px\"\n  },\n  \"model_meta\": {\n    \"name\": \"Our Encoder Transformer (L=12, d=768, h=8)\",\n    \"input_spec\": \"Input: token IDs, shape B × L; + learned position + segment embeddings\",\n    \"output_spec\": \"Class Logits: B × C (optional [CLS] pool), or per-token B × L × d for seq. tagging\"\n  },\n  \"layer_groups\": {\n    \"rule\": \"use color-coded blocks per layer type — keep palette ≤ 5 muted academic colors\",\n    \"color_legend\": [\n      {\n        \"type\": \"Embedding / PatchEmbed\",\n        \"fill\": \"#E0E7FF\",\n        \"border\": \"#6366F1\"\n      },\n      {\n        \"type\": \"Self-Attention\",\n        \"fill\": \"#FEE2E2\",\n        \"border\": \"#DC2626\"\n      },\n      {\n        \"type\": \"Cross-Attention\",\n        \"fill\": \"#FEF3C7\",\n        \"border\": \"#D97706\"\n      },\n      {\n        \"type\": \"Feed Forward / MLP\",\n        \"fill\": \"#D1FAE5\",\n        \"border\": \"#059669\"\n      },\n      {\n        \"type\": \"Norm / Residual\",\n        \"fill\": \"#F3F4F6\",\n        \"border\": \"#6B7280\"\n      }\n    ]\n  },\n  \"layers\": {\n    \"count\": \"5\",\n    \"items\": [\n      {\n        \"id\": \"L1\",\n        \"type\": \"Embedding / PatchEmbed\",\n        \"name\": \"Token + Pos + Type Embed\",\n        \"shape\": \"B × L × 768\"\n      },\n      {\n        \"id\": \"L2\",\n        \"type\": \"Self-Attention\",\n        \"name\": \"Encoder Stack: LN → MHA(h=8) → res → LN → FFN(d_ff=3072) → res (×N=12)\",\n        \"shape\": \"B × L × 768\"\n      },\n      {\n        \"id\": \"L3\",\n        \"type\": \"Norm / Residual\",\n        \"name\": \"Output LayerNorm (after last block)\",\n        \"shape\": \"B × L × 768\"\n      },\n      {\n        \"id\": \"L4\",\n        \"type\": \"Feed Forward / MLP\",\n        \"name\": \"Pool [CLS] token\",\n        \"shape\": \"B × 768\"\n      },\n      {\n        \"id\": \"L5\",\n        \"type\": \"Feed Forward / MLP\",\n        \"name\": \"Classification Head: Linear + dropout + softmax\",\n        \"shape\": \"B × C\"\n      }\n    ]\n  },\n  \"block_style\": {\n    \"shape\": \"rounded rectangle (corner radius 4-6px)\",\n    \"size_rule\": \"blocks of same layer type share identical width; encoder stack shown as a tall column with a brace labeled ×12\",\n    \"border\": \"1.2px solid (use the type's border color)\",\n    \"fill\": \"use the type's fill color (very light tint)\",\n    \"label_text\": \"layer name on first line (sans-serif bold 10-11pt) + tensor shape on second line (monospace italic 9pt)\",\n    \"annotation_text\": \"curly brace on the right of the repeated encoder block with label '× N=12'\"\n  },\n  \"connections\": {\n    \"main_flow\": {\n      \"style\": \"thin black solid arrows (1.2px), left → right through embed → stack → pool → head\",\n      \"arrowhead\": \"small filled triangle\"\n    },\n    \"residual\": {\n      \"enabled\": \"true\",\n      \"style\": \"curved dashed arrow arcing around each (Attn+FFN) sub-block, label '+' at merge\",\n      \"rule\": \"Pre-LN residual around attention and FFN as in modern transformer blocks\"\n    },\n    \"cross_attention\": {\n      \"enabled\": \"false\",\n      \"style\": \"N/A for encoder-only\",\n      \"rule\": \"not used\"\n    }\n  },\n  \"extras\": {\n    \"show_param_count\": {\n      \"enabled\": \"true\",\n      \"rule\": \"note below stack: '≈110M params' (illustrative)\"\n    },\n    \"highlight_novelty\": {\n      \"enabled\": \"false\",\n      \"rule\": \"if true, surround the user's contributed module with a thicker dashed orange border + label 'Ours'\"\n    }\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"tensor shapes in monospace; English labels\",\n      \"white background; no gradient; grayscale-readable shapes\",\n      \"residual skip visually explicit where applicable\"\n    ],\n    \"avoid\": [\n      \"3D blocks, drop shadows, rainbow colors\",\n      \"missing d_model / L / head count on the diagram\"\n    ]\n  }\n}\n",
