        "promptContent": "{\n  \"type\": \"神经网络架构图（neural network architecture diagram）\",\n  \"goal\": \"生成 ViT 架构的论文级示意：PatchEmbed、196 tokens、L=12 自注意力、MLP 头，形状链完整\",\n  \"canvas\": {\n    \"aspect_ratio\": \"16:9\",\n    \"background\": \"white #FFFFFF\",\n    \"outer_padding\": \"60px\"\n  },\n  \"model_meta\": {\n    \"name\": \"ViT-B/16 (ImageNet-1K, supervised)\",\n    \"input_spec\": \"RGB Image 224×224×3\",\n    \"output_spec\": \"Class Logits 1000 (single label classification)\"\n  },\n  \"layer_groups\": {\n    \"rule\": \"color-coded: embedding vs attention vs MLP per legend\",\n    \"color_legend\": [\n      {\n        \"type\": \"Embedding / PatchEmbed\",\n        \"fill\": \"#E0E7FF\",\n        \"border\": \"#6366F1\"\n      },\n      {\n        \"type\": \"Self-Attention\",\n        \"fill\": \"#FEE2E2\",\n        \"border\": \"#DC2626\"\n      },\n      {\n        \"type\": \"Cross-Attention\",\n        \"fill\": \"#FEF3C7\",\n        \"border\": \"#D97706\"\n      },\n      {\n        \"type\": \"Feed Forward / MLP\",\n        \"fill\": \"#D1FAE5\",\n        \"border\": \"#059669\"\n      },\n      {\n        \"type\": \"Norm / Residual\",\n        \"fill\": \"#F3F4F6\",\n        \"border\": \"#6B7280\"\n      }\n    ]\n  },\n  \"layers\": {\n    \"count\": \"6\",\n    \"items\": [\n      {\n        \"id\": \"L1\",\n        \"type\": \"Embedding / PatchEmbed\",\n        \"name\": \"Patch Embed P/16 + [CLS]: 197 tokens\",\n        \"shape\": \"B × 197 × 768\",\n        \"annotation\": \"14×14=196 + CLS\"\n      },\n      {\n        \"id\": \"L2\",\n        \"type\": \"Embedding / PatchEmbed\",\n        \"name\": \"Add 1D Positional + [CLS] prepended\",\n        \"shape\": \"B × 197 × 768\"\n      },\n      {\n        \"id\": \"L3\",\n        \"type\": \"Self-Attention\",\n        \"name\": \"Transformer Encoder (×L=12): LN–MSA–FFN with residuals\",\n        \"shape\": \"B × 197 × 768\"\n      },\n      {\n        \"id\": \"L4\",\n        \"type\": \"Norm / Residual\",\n        \"name\": \"Final LayerNorm\",\n        \"shape\": \"B × 197 × 768\"\n      },\n      {\n        \"id\": \"L5\",\n        \"type\": \"Feed Forward / MLP\",\n        \"name\": \"Take h_CLS (index 0)\",\n        \"shape\": \"B × 768\"\n      },\n      {\n        \"id\": \"L6\",\n        \"type\": \"Feed Forward / MLP\",\n        \"name\": \"MLP Head (2-layer, GELU)\",\n        \"shape\": \"B × 1000\"\n      }\n    ]\n  },\n  \"block_style\": {\n    \"shape\": \"rounded rectangle\",\n    \"size_rule\": \"main encoder shown once with side brace '×12 layers' listing sub-block types\",\n    \"border\": \"1.2px solid by type\",\n    \"fill\": \"light tints per type\",\n    \"label_text\": \"bold name + shape second line in monospace\",\n    \"annotation_text\": \"brace: each block = LN → MSA → res → LN → MLP → res\"\n  },\n  \"connections\": {\n    \"main_flow\": {\n      \"style\": \"left to right: image icon → patch grid glyph → token strip → encoder stack → CLS → logits\",\n      \"arrowhead\": \"small triangle\"\n    },\n    \"residual\": {\n      \"enabled\": \"true\",\n      \"style\": \"dashed residual arcs around each sublayer inside the enc. block (summarized, not 12 separate drawings)\",\n      \"rule\": \"residual every attention and MLP\"\n    },\n    \"cross_attention\": {\n      \"enabled\": \"false\",\n      \"style\": \"N/A\",\n      \"rule\": \"no decoder\"\n    }\n  },\n  \"extras\": {\n    \"show_param_count\": {\n      \"enabled\": \"true\",\n      \"rule\": \"caption near stack: 'ViT-B/16 ≈86M params'\"\n    },\n    \"highlight_novelty\": {\n      \"enabled\": \"false\",\n      \"rule\": \"set true only to highlight a modified stem or novel block, not for stock ViT-B/16\"\n    }\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"197 tokens explicit (or 196 patches + CLS)\",\n      \"patch size 16 and 224/16=14 on diagram margin as tiny note if needed\",\n      \"English only on figure\"\n    ],\n    \"avoid\": [\n      \"confusing CNN stem unless hybrid—keep ViT-pure as specified\",\n      \"omitting spatial token count\"\n    ]\n  }\n}\n",
