        "promptContent": "{\n  \"type\": \"开放世界游戏截图\",\n  \"goal\": \"生成 16:9 横图，观感为 Unreal 级 PBR 实时画面截屏而非预渲染海报，含完整可辨中文 UI\",\n  \"game_meta\": {\n    \"game_name\": \"霜火编年史·极北卷\",\n    \"engine_feel\": \"现代 3A（接近 Unreal 5 Nanite+Lumen 观感）\",\n    \"perspective\": \"第三人称越肩约 2.5m 距离\"\n  },\n  \"scene\": {\n    \"environment\": \"覆雪针叶林缘、中景冰河与断桥、远景覆雪山脉与孤塔\",\n    \"time_of_day\": \"蓝调时刻将尽、西天余暖金边\",\n    \"weather\": \"小雪与风卷雪雾\",\n    \"lighting\": \"冷青主光 + 暖金轮廓光 + 雪地次表面散射\"\n  },\n  \"character\": {\n    \"description\": \"女性游侠主角，银灰长辫、毛领皮甲与弓袋，背向镜头左肩微转、右手握未张弓\",\n    \"position\": \"画面下三分之一居中略左，留出右前侧空间\"\n  },\n  \"ui_elements\": {\n    \"hud\": {\n      \"enabled\": true,\n      \"items\": [\n        \"左下：红条生命+蓝条耐力+圆形简笔头像轮廓\",\n        \"右下：四格扇形技能图标+药水与食物快捷栏\",\n        \"左上：圆形小地图带指北针与当前坐标（中文区名「融雪溪谷」）\",\n        \"右上：任务追踪框体三行「主线：寻找春之露」「距目标 420m」「按 M 打开大地图」\"\n      ]\n    },\n    \"subtitle\": {\n      \"enabled\": true,\n      \"speaker\": \"灵狐伙伴\",\n      \"text\": \"前面结冰的吊桥缺了一截，当心别滑下去。\"\n    },\n    \"interaction_prompt\": {\n      \"enabled\": true,\n      \"text\": \"按 [E] 稳固绳索\"\n    }\n  },\n  \"style\": {\n    \"rendering\": \"PBR + ACES 感 tonemapping + 轻胶片颗粒\",\n    \"color_palette\": \"冰蓝+月白+暖金路标\"\n  },\n  \"aspect_ratio\": \"16:9\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"HUD 与场景透视一致、无悬浮错位\",\n      \"中文无乱码、无英文机翻腔\"\n    ],\n    \"avoid\": [\n      \"无任何 HUD 的纯插画感\",\n      \"同屏 UI 组件超过 8 个主元素\"\n    ]\n  }\n}\n",
