        "promptContent": "{\n  \"type\": \"MMORPG 仙侠游戏截图\",\n  \"goal\": \"16:9 伪游戏内画面，引擎感接近晚近国产自研 MMO 实机，非动画 PV\",\n  \"game_meta\": {\n    \"game_name\": \"九州行·劫火录\",\n    \"engine_feel\": \"高饱和后期国风 MMO（飞剑与轻功系统）\",\n    \"perspective\": \"第三人称略俯视 20°\"\n  },\n  \"scene\": {\n    \"environment\": \"破碎浮空山石与朱红宫阙残垣、脚下流云翻涌、远处天雷云柱\",\n    \"time_of_day\": \"将夜未夜、青紫天光\",\n    \"weather\": \"间歇性灵力碎光如尘\",\n    \"lighting\": \"法宝青金两色主光交叉、人物边缘有轮廓线感但非赛璐璐\"\n  },\n  \"character\": {\n    \"description\": \"可辨识为 Tim Cook 气质的中年男修者：清瘦身形、银灰道袍、简洁束发、无冠，双手捏剑诀、足踏一柄青锋飞剑，面容温和专注，为仙侠美术常见主角类型而非现代写真换脸\",\n    \"position\": \"画面中心偏下，敌向压力来自画外左侧\"\n  },\n  \"ui_elements\": {\n    \"hud\": {\n      \"enabled\": true,\n      \"items\": [\n        \"角色头顶：双向血条（自身绿/敌红）+ 名称「云外客」\",\n        \"屏幕右侧：竖向 1-0 技能与法宝轮，当前高亮「劫火」\",\n        \"左下：聊天窗三条「[世界] 某某：求组团本」「[系统] 你获得 灵石×3」「[战队] 队长：集火」\",\n        \"右上：小地图圆形+东南西北与区域名「墟海·断龙台」\",\n        \"正上：限时条「天劫将至 02:17」\"\n      ]\n    },\n    \"subtitle\": {\n      \"enabled\": true,\n      \"speaker\": \"师父传念\",\n      \"text\": \"劫火将落，先断他剑脉！\"\n    },\n    \"interaction_prompt\": {\n      \"enabled\": true,\n      \"text\": \"按 [R] 祭出镇符\"\n    }\n  },\n  \"style\": {\n    \"rendering\": \"数字国风厚涂材质+实时粒子、略高对比\",\n    \"color_palette\": \"黛青+朱红+金+电青\"\n  },\n  \"aspect_ratio\": \"16:9\",\n  \"constraints\": {\n    \"must_keep\": \"聊天与系统字为简体中文、字体统一无乱码\",\n    \"avoid\": \"日系 JRPG 圆形指令菜单与仙侠 UI 混搭、血条样式与左下聊天重叠\"\n  }\n}\n",
