        "promptContent": "{\n  \"type\": \"贴纸套装 sticker set\",\n  \"goal\": \"生成一张 1:1 总图，内含 16 个可独立裁切的 Q 萌人形贴纸，用于微信聊天面板上传为专辑缩略图或整图切分使用\",\n  \"theme\": \"都市打工人日常（通勤、开会、摸鱼、加班、干饭、躺平、奋斗、吐槽）\",\n  \"style\": {\n    \"rendering\": \"3D Q 萌 + 软光 + 亚光材质，非写实\",\n    \"color_palette\": \"奶茶米+墨灰+薄荷绿点缀，避免高刺激荧光\"\n  },\n  \"sticker_design\": {\n    \"outline\": \"2px 白色外描边\",\n    \"shadow\": \"每枚下方 8% 透明度椭圆软影\",\n    \"with_label\": true,\n    \"label_style\": \"粗圆手写体黑字，置于角色下方空隙，无英文\"\n  },\n  \"layout\": {\n    \"background\": \"浅燕麦色无纹或极淡噪点\",\n    \"grid\": \"4x4\",\n    \"spacing\": \"单元格间距均匀约 3% 边长\",\n    \"aspect_ratio\": \"1:1\"\n  },\n  \"stickers\": {\n    \"count\": 16,\n    \"items\": [\n      \"挤地铁拉吊环的小人+「早八」\",\n      \"趴在工位咖啡续命+「续命」\",\n      \"会议室假装记笔记+「收到」\",\n      \"电脑蓝屏抱头+「崩溃」\",\n      \"偷偷刷手机+「摸鱼」\",\n      \"外卖举筷+「干饭」\",\n      \"深夜台灯敲键盘+「加班」\",\n      \"瘫在沙发+「躺平」\",\n      \"跑步赶打卡+「冲刺」\",\n      \"被老板点名立正+「愣住」\",\n      \"打印机卡纸抓狂+「服了」\",\n      \"周报写满对勾+「搞定」\",\n      \"假期倒数日历+「盼假」\",\n      \"雨天忘带伞+「狼狈」\",\n      \"团建强颜欢笑+「尬笑」\",\n      \"关机关灯下班+「溜了」\"\n    ]\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"每枚独立不粘连，风格统一\",\n      \"中文标签无错字、字号一致\"\n    ],\n    \"avoid\": [\n      \"出现微信绿标或腾讯商标\",\n      \"尺度过界或歧视内容\"\n    ]\n  }\n}\n",
