        "promptContent": "{\n  \"type\": \"贴纸套装 sticker set\",\n  \"goal\": \"一张 4:3 或 1:1 合图，9 个独立 Q 版贴纸，主角为一位虚构的金棕卷发女歌手形象（标志元素：金棕长卷发、红唇、木吉他），不追求摄影级像真，整体走可爱卡通风\",\n  \"theme\": \"演唱会与歌迷路演梗、友谊手环、黑胶与话筒\",\n  \"style\": {\n    \"rendering\": \"扁平+少量 cel 描边+软投影，色块干净\",\n    \"color_palette\": \"金棕发+正红+墨黑+米白，点缀薄荷绿与薰衣草紫\"\n  },\n  \"sticker_design\": {\n    \"outline\": \"2.5px 奶白外轮廓\",\n    \"shadow\": \"无或极轻，避免 3D 过厚\",\n    \"with_label\": true,\n    \"label_style\": \"下方中文手写感短词，2~4 字，深棕\"\n  },\n  \"layout\": {\n    \"background\": \"浅灰蓝格纹纸纹理\",\n    \"grid\": \"3x3\",\n    \"spacing\": \"均分留白\",\n    \"aspect_ratio\": \"1:1\"\n  },\n  \"stickers\": {\n    \"count\": 9,\n    \"items\": [\n      \"Q 版女歌手握木吉他张嘴唱+「开唱」\",\n      \"转圈大裙摆简形+「名场面」\",\n      \"猫耳发箍抱小猫+「猫奴」\",\n      \"暴雨中撑伞+「雨演」\",\n      \"手腕上套彩色纸手环+「换手环」\",\n      \"黑胶唱片与唱针+「黑胶」\",\n      \"心形手势对镜头+「比心」\",\n      \"笔记本写满歌词+「填词」\",\n      \"向台下递话筒+「大合唱」\"\n    ]\n  },\n  \"constraints\": {\n    \"must_keep\": \"九格同一线宽与色板、每图可单独圆形裁切使用\",\n    \"avoid\": \"写真实公众人物全名在画面醒目位置、可识别商标 album 封面 1:1 复刻\"\n  }\n}\n",
