        "promptContent": "{\n  \"type\": \"国潮风饮料瓶标签设计\",\n  \"goal\": \"生成 4:5 竖版产品主图，瓶身与标签为视觉核心，可送印前审视\",\n  \"brand\": {\n    \"name\": \"荔潮 LITCHI WAVE\",\n    \"positioning\": \"国潮果味气泡水、年轻国风社交饮\",\n    \"product_name\": \"岭南无核荔枝汽泡水\",\n    \"product_subtitle\": \"ZERO SUGAR SPARKLING\",\n    \"volume\": \"330ml\"\n  },\n  \"bottle\": {\n    \"form\": \"短颈透明圆肩玻璃瓶 + 香槟金旋盖、瓶肩一圈微菱形防滑纹\",\n    \"material\": \"透明高白料玻璃，液面淡粉、细密气泡上涌可见\"\n  },\n  \"label_design\": {\n    \"style\": \"前景工笔荔枝壳纹理 + 后景淡墨山影，大留白，底部窄条为信息区\",\n    \"primary_color\": \"荔枝壳朱红、墨青绿、金箔勾边、米白标底\",\n    \"background_color\": \"米白 #F3EFE6\",\n    \"illustration\": \"主荔枝剖面露出晶莹果肉，旁一枝小叶与远处抽象海浪线，暗示「潮」\",\n    \"typography\": \"中文标题为粗宋变体、英文为窄无衬线大写、营养表为 6.5pt 黑体可辨行距\",\n    \"info_strip_bottom\": \"每 100ml 能量、糖、纳、零糖声明、生产许可占位条、成分：水、赤藓糖醇、浓缩荔枝汁、二氧化碳等\"\n  },\n  \"scene\": {\n    \"background\": \"深竹编餐垫、半只去皮荔枝、一小碟海盐颗粒暗示清爽\",\n    \"lighting\": \"自然窗光柔箱，右侧微逆光勾瓶体\"\n  },\n  \"format\": {\n    \"aspect_ratio\": \"4:5\",\n    \"composition\": \"瓶体略向镜头 8° 倾角，主标面正对镜头、上下信息条不弯曲畸变\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"国潮与日式书法不可混为同一标题体系\",\n      \"营养条字级小但可辨，不压扁为糊块\",\n      \"液色与品名自然对应\"\n    ],\n    \"avoid\": [\n      \"标签贴歪或起翘严重（除非做撕贴创意）\",\n      \"插画覆盖品牌名可辨度\",\n      \"背景艳粉抢镜\"\n    ]\n  }\n}\n",
