        "promptContent": "{\n  \"type\": \"西式现代精酿瓶标设计\",\n  \"goal\": \"生成 4:5 竖版，突出纸标专色与烫印层次，可拆正背一体展开想象\",\n  \"brand\": {\n    \"name\": \"雾港酿造 Mist Harbor\",\n    \"positioning\": \"小型城市连锁精酿、主打西海岸 IPA\",\n    \"product_name\": \"雾港印度淡色艾尔\",\n    \"product_subtitle\": \"MIST HARBOR WEST COAST IPA\",\n    \"volume\": \"470ml\"\n  },\n  \"bottle\": {\n    \"form\": \"深琥珀长颈啤酒瓶，瓶颈印一次性促销环「新鲜灌装」小字\",\n    \"material\": \"玻璃 + 凝结冷水珠、液面 2cm 酒头泡\"\n  },\n  \"label_design\": {\n    \"style\": \"木刻版画海浪 + 矢量灯塔光束，橙黄与靛蓝专色，边缘粗白描刀切感\",\n    \"primary_color\": \"橙黄、深靛、米纸底\",\n    \"background_color\": \"主标纸芯 #EEE3CE\",\n    \"illustration\": \"灯塔、涌浪、一行迁徙海鸟、远处城廓剪影\",\n    \"typography\": \"主标题为紧凑西文 slab serif，中文副行黑体，酒精度 6.5% vol 与 IBU 68 在正面下三角排布\",\n    \"info_strip_bottom\": \"背标（画面可见一侧卷角示意）：原麦汁浓度、保质期、厂名、过量饮酒提示、扫码溯源框线\"\n  },\n  \"scene\": {\n    \"background\": \"老橡木条、黄铜开瓶器、两只空杯一倒扣现冷凝\",\n    \"lighting\": \"单灯侧顶硬光、强调瓶标浮雕烫边\"\n  },\n  \"format\": {\n    \"aspect_ratio\": \"4:5\",\n    \"composition\": \"瓶略偏左，右侧留白给长投影，纸标不跨越瓶肩合缝线错位\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"正面保留清晰品牌名、品类、度数字号\",\n      \"西文与中文层级分明，不互抢\",\n      \"酒液颜色与「西海岸 IPA 琥珀清亮」一致\"\n    ],\n    \"avoid\": [\n      \"国潮云纹与木刻版画风混搭\",\n      \"信息法规字过小不可读\"\n    ]\n  }\n}\n",
