        "promptContent": "{\n  \"type\": \"品牌识别系统板\",\n  \"goal\": \"生成一张可作为 VI summary 的品牌板，3:4 竖版，四宫格分区清晰\",\n  \"brand\": {\n    \"name\": \"清篱\",\n    \"tagline\": \"一味草木，半日清欢\",\n    \"industry\": \"新中式冲饮与草本小罐茶\",\n    \"personality\": \"克制、温润、可信赖、略文人气质\"\n  },\n  \"regions\": {\n    \"logo\": {\n      \"position\": \"左上大区 约 40% 宽\",\n      \"primary_logo\": \"「清」字作行书骨架，与三片简笔篱叶组成圆形章；横排字标为「清篱」二字 + 英文 CHING LI 全大写 3pt 行\",\n      \"secondary_logos\": [\n        \"纯图形圆形章（无字）\",\n        \"竖排「清 / 篱」与圆章左右组合\",\n        \"深绿底反白一版\"\n      ],\n      \"background_test\": \"左半浅米底 + 右半深松绿底各放一版主组合\"\n    },\n    \"color_palette\": {\n      \"position\": \"右上\",\n      \"primary\": [\n        \"#2F4F4F 松烟绿\",\n        \"#C7B89E 米汤白\"\n      ],\n      \"secondary\": [\n        \"#8C9A8E 鼠尾草灰绿\",\n        \"#1A1A1A 墨点黑\"\n      ],\n      \"swatch_design\": \"圆角色块 + HEX + 中文名 + 5% 白细边\"\n    },\n    \"typography\": {\n      \"position\": \"左下\",\n      \"headline_font\": \"中文为类似思源宋的 modern serif 横排，英文衬线为 Cormorant 气质\",\n      \"body_font\": \"中文为类似 PingFang 的 clean sans 正文 9pt 演示\",\n      \"demo_block\": \"Aa 清茶回甘 · Brew calm，0123456789，一行长条款假文占位\"\n    },\n    \"applications\": {\n      \"position\": \"右下\",\n      \"mockups\": [\n        \"名片正反面，正面大面积留白 + 松烟绿细边，反面小圆章\",\n        \"牛皮纸小罐茶包装筒顶视 + 标贴\",\n        \"微信公众号封面图 16:9 缩略：茶汤显微距 + 一句话标题位\"\n      ]\n    }\n  },\n  \"style\": {\n    \"art_style\": \"现代极简品牌板，浅米背景 + 5% 噪点，细灰 8px 基线格作为装饰\",\n    \"grid\": \"淡灰 1pt 线仅出现在 logo 与色板区外沿\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"色板内 HEX 数字清晰可读，≤6 主色\",\n      \"四个区块边界不糊在一起\",\n      \"mockup 光照统一为左上 45° 软光\"\n    ],\n    \"avoid\": [\n      \"书法字与几何 logo 在 mockup 上乱缩放变形\",\n      \"同屏 >2 个字体家族\",\n      \"国潮红金大面积喧宾\"\n    ]\n  }\n}\n",
