        "promptContent": "{\n  \"type\": \"品牌识别系统板\",\n  \"goal\": \"生成一张社区咖啡馆视觉识别单页，偏温暖工业风，3:4\",\n  \"brand\": {\n    \"name\": \"砖缝光 Bricklight\",\n    \"tagline\": \"在裂缝里，借一道日常的光\",\n    \"industry\": \"独立精品咖啡与烘焙\",\n    \"personality\": \"实在、好聊、不装\"\n  },\n  \"regions\": {\n    \"logo\": {\n      \"position\": \"左上\",\n      \"primary_logo\": \"B 与 L 共用笔触形成砖缝，一道斜向光束负形从缝中穿过；下排小字「BRICKLIGHT COFFEE」\",\n      \"secondary_logos\": [\n        \"仅光束 + 砖线图标\",\n        \"横排长字标去图标\",\n        \"单黑版反白在烧橙色底\"\n      ],\n      \"background_test\": \"浅暖灰 + 深燧石黑\"\n    },\n    \"color_palette\": {\n      \"position\": \"右上\",\n      \"primary\": [\n        \"#1E1E1E 燧石黑\",\n        \"#D36135 窑变橙\"\n      ],\n      \"secondary\": [\n        \"#EDE6DB 米窑白\",\n        \"#5C6670 钢蓝灰\"\n      ],\n      \"swatch_design\": \"长条色带 + HEX + 用途小字如「主背景」「强强调」\"\n    },\n    \"typography\": {\n      \"position\": \"左下\",\n      \"headline_font\": \"无衬线类似 Space Grotesk 的略几何英文 + 中文黑体\",\n      \"body_font\": \"中文小字号说明体\",\n      \"demo_block\": \"Menu · 今日手冲 · 01234，三行假菜单价目\"\n    },\n    \"applications\": {\n      \"position\": \"右下\",\n      \"mockups\": [\n        \"外带纸杯 + 热杯套，logo 不绕杯过满一圈\",\n        \"门头发光字夜间 mockup 小方图\",\n        \"微信小程序码立牌，上方一行「点单取号」小字，整体留白 40%\"\n      ]\n    }\n  },\n  \"style\": {\n    \"art_style\": \"水泥质感浅底 + 极轻划痕纹理\",\n    \"grid\": \"仅用于 logo 与 app 区对齐的淡灰 12 列\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"HEX 与圆角色块对应\",\n      \"四区呼吸感，避免色块糊满\",\n      \"杯上 logo 不跨越杯缝可识别区\"\n    ],\n    \"avoid\": [\n      \"过强锈迹与脏渍纹理\",\n      \"超过 6 个品牌色点\"\n    ]\n  }\n}\n",
