        "promptContent": "{\n  \"type\": \"护肤精华单瓶包装设计\",\n  \"goal\": \"生成 4:5 竖版，突出玻璃瓶折射与软光，可兼作礼盒电商主图\",\n  \"brand\": {\n    \"name\": \"东篱 DONG LI LAB\",\n    \"positioning\": \"东方高功效护肤 + 实验室透明配方叙事\"\n  },\n  \"product\": {\n    \"name\": \"光感紧致修护精华\",\n    \"subtitle\": \"LUMINANCE FIRMING SERUM\",\n    \"volume\": \"30ml 滴管瓶 + 同系列 15g 修护眼霜小罐（礼盒内景）\",\n    \"form\": \"主瓶为略微收腰圆柱磨砂瓷白玻璃、滴管盖为亚光香槟金、肩部一圈暗刻回纹\",\n    \"key_ingredient\": \"2% 专研复合肽 + 0.2% 白藜芦醇\"\n  },\n  \"design\": {\n    \"bottle_material\": \"外壁磨砂、内壁透明可见淡香槟色料体\",\n    \"label_material\": \"和纸感不干胶、烫雾金logo、竖排小字成分表可辨行距\",\n    \"primary_color\": \"#6B7A7A 天青灰\",\n    \"accent_color\": \"香槟金 #C6A15B\",\n    \"typography\": \"中文类似思源黑极细 + 英文全大写无衬线 6pt 级\"\n  },\n  \"outer_box\": {\n    \"enabled\": \"true\",\n    \"shape\": \"对开磁吸礼盒，外壁布纹卡纸、中央烫金小篆「东篱」\",\n    \"finish\": \"侧棱深灰、内衬鼠尾草绿绒，半开 35° 露内部槽位\"\n  },\n  \"scene\": {\n    \"background\": \"浅天青渐变无缝纸、前景薄真丝与两块磨砂亚克力错层\",\n    \"props\": \"一根新鲜石斛切片与一支小号玻璃量筒作理性点缀\",\n    \"lighting\": \"双柔箱 + 顶偏逆光勾瓶肩\"\n  },\n  \"format\": {\n    \"aspect_ratio\": \"4:5\",\n    \"composition\": \"滴管瓶前景略右、礼盒左后、眼霜小罐在盒内发柔高光\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"料体与玻璃折射自然\",\n      \"全页主色 ≤3 大色域\",\n      \"外盒与瓶身字标为同一系谱\",\n      \"容量与品名在瓶身可读不糊\"\n    ],\n    \"avoid\": [\n      \"药械化过度医学器械联想\",\n      \"金边俗艳反光\",\n      \"瓶身比例失真如玩具\"\n    ]\n  }\n}\n",
