        "promptContent": "{\n  \"type\": \"吉祥物品牌识别套装\",\n  \"goal\": \"生成一张多面板 IP 套卡，3:4，气质喜庆但不艳俗，适合印周边手册封底\",\n  \"ip\": {\n    \"name\": \"小脊兽蹲蹲\",\n    \"tagline\": \"殿顶小小守护，展里陪你慢逛\",\n    \"personality\": \"好奇、爱热闹、对传统文化有点小得意\",\n    \"brand_owner\": \"故宫宫廷文化 · 青少导览与文创子线（概念演练）\"\n  },\n  \"mascot\": {\n    \"form\": \"圆体小脊兽，身体蛋形，四腿短，尾为波浪状琉璃火焰纹；额间一点宝石蓝圆点，头顶一截迷你屋脊与吻兽剪影；无写实兽骨结构，整体玩具感。\",\n    \"color_palette\": \"明黄、琥珀金、宝蓝、宫墙灰、少量朱砂点缀\",\n    \"rendering\": \"2D 卡通厚涂，边缘清线，无 3D 强反光\"\n  },\n  \"regions\": {\n    \"hero\": {\n      \"position\": \"左上 45%\",\n      \"content\": \"全身主图 + 旁竖排名「小脊兽蹲蹲」+ 小字「殿顶灵感 · 非文物本体」\",\n      \"background\": \"极浅米色 + 重复浅云纹，不压主体\"\n    },\n    \"three_view\": {\n      \"position\": \"右上\",\n      \"content\": \"等比例正面 / 侧面 / 背面三图横排，屋脊在头顶的透视一致，尾焰弯向一致\",\n      \"label\": \"FRONT / SIDE / BACK\"\n    },\n    \"expressions\": {\n      \"position\": \"左下 通栏\",\n      \"count\": \"6\",\n      \"items\": [\n        \"开心龇小牙\",\n        \"好奇歪头看展柜\",\n        \"被人群吓成小饼脸\",\n        \"打哈欠犯困但坚持听完讲解\",\n        \"害羞捂脸（短手挡一半）\",\n        \"认真举小令旗（巡线安全员梗）\"\n      ]\n    },\n    \"applications\": {\n      \"position\": \"右下\",\n      \"items\": [\n        \"和纸胶带卷展开一段，主图案重复小脊兽\",\n        \"金属书签，镂空小脊兽吊牌\",\n        \"展厅门口易拉宝上半：展名位 + 小脊兽作揖\",\n        \"微信表情包静帧 256px 方图一格（呲牙笑）\"\n      ]\n    }\n  },\n  \"style\": {\n    \"background\": \"米色纸感 + 5% 杂点，细淡灰 6 列格作为对齐参考不印刷\",\n    \"typography\": \"中文圆体 + 一行行楷副标题，英文全小写说明\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"全页同一角色比例尺统一\",\n      \"三视图无结构性矛盾\",\n      \"表情不扭曲成另一物种\",\n      \"微信格注明为方图用途\"\n    ],\n    \"avoid\": [\n      \"与真实脊兽照片拼贴\",\n      \"表情过度挤压五官\",\n      \"用未授权实景照片做底\"\n    ]\n  }\n}\n",
