        "promptContent": "{\n  \"type\": \"吉祥物品牌识别套装\",\n  \"goal\": \"生成一张以黄色袋鼠骑手为核心的周边与 UI 静帧板，2D+轻 3D 混合，偏广告摄影 mockup 拼贴感\",\n  \"ip\": {\n    \"name\": \"美团小袋鼠·速达\",\n    \"tagline\": \"好饭，正在路上\",\n    \"personality\": \"冲劲、可爱、路熟、偶尔搞笑翻车\",\n    \"brand_owner\": \"美团外卖 本地即时配送（品牌演练稿）\"\n  },\n  \"mascot\": {\n    \"form\": \"站立袋鼠短耳大头，明黄主色、黑长尾、黑手套脚套；胸前圆形白色区域留给「送」字抽象符号而非真实商标；加小黄盔与可拆卸小型保温箱。\",\n    \"color_palette\": \"#FFCC00 美团黄、#000000 黑、#FFFFFF 白、少量 #00C853 状态绿\",\n    \"rendering\": \"3D Q 形卡通，塑料玩具光泽适度，地面有柔影\"\n  },\n  \"regions\": {\n    \"hero\": {\n      \"position\": \"左上\",\n      \"content\": \"主视觉奔跑姿态，单手持手机导航（手机屏为亮块无 UI），脚边速度线\",\n      \"background\": \"白到浅黄渐变，无城市实景照片\"\n    },\n    \"three_view\": {\n      \"position\": \"右上\",\n      \"content\": \"FRONT / SIDE / BACK 三图，注意保温箱背带交叉方式一致\",\n      \"label\": \"FRONT / SIDE / BACK\"\n    },\n    \"expressions\": {\n      \"position\": \"左下\",\n      \"count\": \"6\",\n      \"items\": [\n        \"准时骄傲抬头\",\n        \"看地图皱眉\",\n        \"雨中小委屈撑伞\",\n        \"电梯里挤成饼\",\n        \"收到用户好评心心眼\",\n        \"空翻庆祝（Q 版夸张）\"\n      ]\n    },\n    \"applications\": {\n      \"position\": \"右下\",\n      \"items\": [\n        \"电动车前挡风透明罩印轮廓剪影\",\n        \"大保温袋平面展开印刷稿含出血线提示\",\n        \"微信服务通知小红点边上小袋鼠探头脑洞（为示意）\"\n      ]\n    }\n  },\n  \"style\": {\n    \"background\": \"浅灰方格 + 大留白，商业提案风\",\n    \"typography\": \"黑体 + 黄黑条标题\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"不复制真实未授权摄影人像\",\n      \"全页色彩与现网黄黑体系一致不漂移\",\n      \"小袋鼠在各区轮廓线宽一致\"\n    ],\n    \"avoid\": [\n      \"在图中写不可辨识小字当 fake 条款\",\n      \"与竞品配色混淆\"\n    ]\n  }\n}\n",
