        "promptContent": "{\n  \"type\": \"动漫立项 Pitch Board\",\n  \"goal\": \"生成一张国产回合制 RPG 对外 pitch 单页，信息分区清晰、可直接印 deck 首页\",\n  \"ip\": {\n    \"title\": \"星枢编年史\",\n    \"title_localized\": \"Chronicle of the Astral Spindle\",\n    \"tagline\": \"改写星轨者，自为人间立法\",\n    \"logline\": \"在人造星空之下，符师少女与废铁机甲骑士结伴穿越折叠城邦，向篡夺天枢的教团索回一夜真正的黑夜。\",\n    \"genre\": \"东方科幻 / 公路冒险 / 回合制 RPG\"\n  },\n  \"regions\": {\n    \"main_kv\": {\n      \"position\": \"上半约 60%\",\n      \"content\": \"青金夜幕下巨型齿轮状空间站悬于云海，前景三人小队逆风前行：持符箓长幡的少女、提光束骑枪覆盖锈甲的青年、掌浮动八卦盘的兽耳学者；远处城市霓虹呈环形梯田状\",\n      \"style\": \"电影级 anime 厚涂 + 体积雾 + 高对比边缘光\"\n    },\n    \"character_cards\": {\n      \"position\": \"左下 35% 宽\",\n      \"count\": \"3\",\n      \"items\": [\n        \"离昭 · 符师 · 可改写局部重力场，但每战消耗「记忆丝」\",\n        \"沈铸 · 巡游骑士 · 驾驶可拼接模块机甲，前重装侦查\",\n        \"见潮 · 天枢学者 · 兽耳、推演敌回合意图，团队大脑\"\n      ],\n      \"card_design\": \"圆角方卡：胸像 + 名 + 一句定位\"\n    },\n    \"world_setting\": {\n      \"position\": \"右下 35% 宽\",\n      \"content\": \"「枢城」为多层折叠都市，昼夜由天枢教团发放；主矛盾为被剥夺的星空权与地底旧神残渣。\",\n      \"extras\": [\n        \"缩略地形图：三层环形城区 + 一条垂直电梯井\",\n        \"三图标：符箓、机甲插槽、星轨条资源\"\n      ]\n    },\n    \"title_block\": {\n      \"position\": \"顶距上缘 4% 居中\",\n      \"components\": [\n        \"主标题行「星枢编年史」\",\n        \"副行 Chronicle of the Astral Spindle 略小全大写\",\n        \"tagline 斜体中文小字\"\n      ]\n    },\n    \"footer_meta\": {\n      \"position\": \"最底 3%\",\n      \"content\": \"NEBULA PULSE STUDIO · 单页概览 2026 · 本页为创作演练文件\"\n    }\n  },\n  \"style\": {\n    \"art_style\": \"现代 anime 半写实 + 厚涂 + 深空青与熔金对撞\",\n    \"color_palette\": \"#0A1628 深靛、#3EC9FF 电青、#C9A227 星金、#E8DCCD 月白\",\n    \"typography\": \"中文标题有衬线感 + 英文无衬线混排，正文 8pt 级灰色\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"KV 区不低于画面高度 50%\",\n      \"三角色卡视觉风格统一、线宽一致\",\n      \"含 tagline 与 logline 文案区，不得只剩图画\"\n    ],\n    \"avoid\": [\n      \"区块挤占 KV 至低于 40%\",\n      \"同屏主色超过 4 大色块\",\n      \"角色卡与 KV 中人物设计不一致\"\n    ]\n  }\n}\n",
