        "promptContent": "{\n  \"type\": \"7 日穿搭 lookbook\",\n  \"goal\": \"生成一张可发小红书 / Instagram 的 7 日 lookbook 信息图，3:4\",\n  \"title_block\": {\n    \"main_title\": \"一周穿什么 · 时代巡演系灵感\",\n    \"subtitle\": \"7 days · sequins & knits\",\n    \"position\": \"顶部居中\"\n  },\n  \"subject\": {\n    \"model\": \"年轻女性，金色长卷发，五官为原创动漫感偏写真，不追求与任何真人像素级一致；身材匀称偏修长\",\n    \"consistency\": \"7 格内为同一人、同脸型与发型\"\n  },\n  \"layout\": {\n    \"format\": \"上 4 格 + 下 3 格错位，格间 8px 发丝线\",\n    \"panel_count\": 7,\n    \"panel_design\": {\n      \"label_top\": \"DAY 1 / MON 至 SUN 大写，角落小号\",\n      \"outfit_caption\": \"每格下缘一行短英文风格名 + 中文 4 至 6 字\"\n    }\n  },\n  \"outfits\": [\n    {\n      \"day\": 1,\n      \"label\": \"MON\",\n      \"style\": \"亮片短上衣 + 高腰阔腿黑裤 + 细跟靴，舞台反光背景\"\n    },\n    {\n      \"day\": 2,\n      \"label\": \"TUE\",\n      \"style\": \"奶油白粗针织 cardi + 牛仔喇叭裤 + 棕皮带，暖室内窗光\"\n    },\n    {\n      \"day\": 3,\n      \"label\": \"WED\",\n      \"style\": \"酒红丝绒迷你裙 + 过膝长靴，剧院幕布前\"\n    },\n    {\n      \"day\": 4,\n      \"label\": \"THU\",\n      \"style\": \"黑白条纹 T + 卡其百慕大短裤 + 复古运动鞋，城市街拍\"\n    },\n    {\n      \"day\": 5,\n      \"label\": \"FRI\",\n      \"style\": \"墨绿丝质衬衫 + 黑直筒西裤 + 小方巾，轻正式晚餐场景\"\n    },\n    {\n      \"day\": 6,\n      \"label\": \"SAT\",\n      \"style\": \"格纹迷你连衣裙 + 牛仔外套系腰 + 白球鞋，公园草坪\"\n    },\n    {\n      \"day\": 7,\n      \"label\": \"SUN\",\n      \"style\": \"灰连帽卫衣 + 软裤 + 羊毛袜居家，咖啡杯小道具，松弛感\"\n    }\n  ],\n  \"style\": {\n    \"art_style\": \"日杂时尚平拍 + 米色无缝纸 + 轻后期颗粒\",\n    \"color_palette\": \"米白、黑、金闪点缀、低饱和红绿\"\n  },\n  \"footer\": {\n    \"summary\": \"工作日少量亮片点缀，周末回到针织与软材质\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"7 格同一人可识别，服装差异明显不重复\",\n      \"每格有全身或膝上全身，不裁头\",\n      \"主色板不掺荧光粉绿\"\n    ],\n    \"avoid\": [\n      \"7 人七张脸\",\n      \"格内小字多过两行\"\n    ]\n  }\n}\n",
