        "promptContent": "{\n  \"type\": \"9 宫格 self-care 清单\",\n  \"goal\": \"生成一张 3×3 的每日自我关照信息图，中文标题，插画风统一，3:4 竖版\",\n  \"title_block\": {\n    \"main_title\": \"每天 9 件温柔小事\",\n    \"subtitle\": \"不必全做，完成 3 个也很好\",\n    \"position\": \"顶部居中\"\n  },\n  \"layout\": {\n    \"format\": \"3x3 grid 等分，圆角 12px\",\n    \"panel_count\": 9\n  },\n  \"outfits\": [\n    {\n      \"label\": \"1\",\n      \"style\": \"8 杯温水，插画风玻璃瓶与小水滴\"\n    },\n    {\n      \"label\": \"2\",\n      \"style\": \"10 分钟拉伸，瑜伽垫简笔小人\"\n    },\n    {\n      \"label\": \"3\",\n      \"style\": \"阳光下慢走 15 分钟，小路与树影\"\n    },\n    {\n      \"label\": \"4\",\n      \"style\": \"3 次深呼吸，鼻腔气流示意线稿\"\n    },\n    {\n      \"label\": \"5\",\n      \"style\": \"写下 1 件感谢，小本子与笔\"\n    },\n    {\n      \"label\": \"6\",\n      \"style\": \"听一首老歌，耳机与音符\"\n    },\n    {\n      \"label\": \"7\",\n      \"style\": \"用微信发一句问候给家人，小手机与爱心气泡（界面抽象无具体头像）\"\n    },\n    {\n      \"label\": \"8\",\n      \"style\": \"读 10 页纸书，翻开书页与茶杯\"\n    },\n    {\n      \"label\": \"9\",\n      \"style\": \"11 点躺下，调暗台灯与眼罩\"\n    }\n  ],\n  \"style\": {\n    \"art_style\": \"扁平柔和插画 + 大圆角 + 无描边或极细线\",\n    \"color_palette\": \"雾粉、灰绿、奶油白、浅焦糖\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"9 格等面积，图标风格一致\",\n      \"每格主文案不超过 8 个汉字或等价长度\",\n      \"无真人照片\"\n    ],\n    \"avoid\": [\n      \"高对比警示色\",\n      \"格内出现两种插画语言混用\"\n    ]\n  }\n}\n",
