        "promptHint": "28 岁齐肩黑发、米白衬衫为跨格识别锚；中央大格为影棚柔光摄影，四角依次为日式 anime、大写意水墨、伦勃朗式古典油画、赛博霓虹氛围，一图展示同一面容的媒介实验墙。",
        "promptContent": "{\n  \"type\": \"5 格混合风格拼贴\",\n  \"goal\": \"生成一张多风格拼贴图，同一中国女性为唯一主体，仅画风变化，中央格最大\",\n  \"subject\": {\n    \"description\": \"同一位东亚女性，约 28 岁，齐肩直黑发，细眉，米白棉质衬衫，双手自然交叠于腹前，表情平静带浅笑。禁止更换发型与衣色以便跨格识别。\",\n    \"consistency_rule\": \"五格中五官比例与衣款一致，仅渲染手法不同\"\n  },\n  \"layout\": {\n    \"format\": \"中央大格 + 四角小格，整体衬于浅米灰纸纹\",\n    \"panel_count\": 5,\n    \"label_position\": \"每格下缘居中\",\n    \"label_design\": \"9pt 等宽大写英文 + 中文小标，黑字白底小圆角条\"\n  },\n  \"panels\": [\n    {\n      \"position\": \"center\",\n      \"style\": \"高分辨率影棚柔光摄影，白背景，可辨肤质与布褶\",\n      \"label\": \"PHOTO · 写真\"\n    },\n    {\n      \"position\": \"top-left\",\n      \"style\": \"现代日式 anime 赛璐璐，清晰线稿、平涂、腮红线\",\n      \"label\": \"ANIME · 日漫\"\n    },\n    {\n      \"position\": \"top-right\",\n      \"style\": \"大写意浅绛水墨，留白烟雾感，仅面部略烘染赭石\",\n      \"label\": \"INK · 水墨\"\n    },\n    {\n      \"position\": \"bottom-left\",\n      \"style\": \"古典油画，伦勃朗式侧光，深褐底，厚涂笔触可见\",\n      \"label\": \"OIL · 油画\"\n    },\n    {\n      \"position\": \"bottom-right\",\n      \"style\": \"赛博朋克，霓虹品红与电青边光，轻微故障纹理与细网格 HUD，仅作氛围不挡脸\",\n      \"label\": \"CYBER · 赛博\"\n    }\n  ],\n  \"global_constraints\": {\n    \"background\": \"整张大底为统一 #F2EFE8 细颗粒纸感，小格间 10px 浅灰缝\",\n    \"spacing\": \"白缝锚定，避免每格自设无关底色\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"五格中一眼为同人不同画风而非五人\",\n      \"赛博格不过度加面罩与义体，保持面部可辨\",\n      \"标签不压五官中央\"\n    ],\n    \"avoid\": [\n      \"某一格变男性或变童装\",\n      \"水墨格出现对话框漫画符号\",\n      \"中央格过暗淹没识别锚\"\n    ]\n  }\n}\n",
