        "promptContent": "{\n  \"type\": \"便当格 / Bento grid 高密度模块化信息图\",\n  \"goal\": \"单张 3:4 竖图把 iPhone 16 Pro 的屏幕、SoC、摄像、机身材质与起售价讲清楚，像 iOS widget 满屏但文案克制\",\n  \"canvas\": {\n    \"aspect_ratio\": \"3:4 portrait\",\n    \"background\": \"warm off-white #F5F2EC\",\n    \"global_corner_radius\": \"24px\",\n    \"module_gap\": \"16px\"\n  },\n  \"header\": {\n    \"main_title\": \"iPhone 16 Pro 全方位解析：手感、算力、影像一次看懂\",\n    \"subtitle\": \"钛金属 · A18 Pro · 三摄系统 · iOS 18 同步亮点（参数以 Apple 公开展示为口径，图内数字为设计示意）\",\n    \"title_position\": \"top-left, large bold sans-serif\"\n  },\n  \"palette\": {\n    \"primary\": \"deep ink #1A1A1A\",\n    \"accent\": \"tech copper #C67B4E\",\n    \"module_tints\": [\n      \"soft sand #EBE3D5\",\n      \"muted sage #C7D3C0\",\n      \"dusty blue #B4C5D6\",\n      \"warm peach #F2D4C4\"\n    ],\n    \"rule\": \"module_tints 轮换，accent 仅用于大数字与 CTA 级关键词\"\n  },\n  \"layout\": {\n    \"style\": \"asymmetric bento with one 2x2 hero\",\n    \"module_count\": \"8\",\n    \"grid\": \"1 hero 2x2 左上; 右列上下各一 1x2+1x1; 下区两排填满\",\n    \"alignment\": \"invisible 12-column grid, strict gap\"\n  },\n  \"modules\": [\n    {\n      \"id\": \"M1-hero\",\n      \"size\": \"large (2x2)\",\n      \"role\": \"TOP 1 / 主推荐\",\n      \"content\": \"左侧钛金属原色 Pro 产品侧视 + 主摄模组特写; 三行加粗: 「更轻的钛框」「5 倍长焦可日常」「4K/120 杜比视界」; 星评五星; 小字: 建议容量 256 GB 起\"\n    },\n    {\n      \"id\": \"M2\",\n      \"size\": \"medium (1x2 vertical)\",\n      \"role\": \"屏幕与显示\",\n      \"content\": \"标题「ProMotion 与峰值亮度」: 极细示意曲线表示刷新率, 大数字 120 Hz 与 2000+ nit 样例标注（示意）+ 小字: 常亮显示、文字锐度\"\n    },\n    {\n      \"id\": \"M3\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"关键数字\",\n      \"content\": \"巨大数字「A18 Pro」+ 小标签「3 nm 级 第二代」+ 小图标 CPU/GPU/NE\"\n    },\n    {\n      \"id\": \"M4\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"接口 / 体验\",\n      \"content\": \"四个迷你图标+标签: ProRes / USB-C / 空间视频 / 操作按钮(示意)\"\n    },\n    {\n      \"id\": \"M5\",\n      \"size\": \"medium (2x1 wide)\",\n      \"role\": \"多摄对比条\",\n      \"content\": \"横向三枚镜头剪影 + 0.5× / 1× / 5× 小字, 用浅灰条表示焦段, 高亮 5× 日常可用人像\"\n    },\n    {\n      \"id\": \"M6\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"起售价提示\",\n      \"content\": \"人民币「¥7,999 起(示意)」+ 行小字: 以官网实时为准 + 以旧换新可再减\"\n    },\n    {\n      \"id\": \"M7\",\n      \"size\": \"medium (1x2)\",\n      \"role\": \"iOS 18 同屏要点\",\n      \"content\": \"列表 3 条: 锁屏/控制项自定义; 与 Mac/iPad 连续互通小图标; 端侧与云端 AI 用隐私图标点到为止\"\n    },\n    {\n      \"id\": \"M8\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"Footer\",\n      \"content\": \"小字: 配壳膜更保值 · 下一张滑看配件清单 →; 不放入真实 URL\"\n    }\n  ],\n  \"module_internal_style\": {\n    \"padding\": \"20px\",\n    \"typography\": \"Inter / 思源黑; module 内小标题 14px 粗, 正文 12px\",\n    \"rule\": \"每格必有 micro-title 与至少一个小图形或数字\",\n    \"imagery\": \"产品为示意渲染风, 非实拍商标特写\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"统一 24px 圆角\",\n      \"8 个模块都填实\",\n      \"至少一格里含类条形对比或大数字\"\n    ],\n    \"avoid\": [\n      \"全图渐变玻璃拟态破坏 bento 简洁\",\n      \"与 Apple 官方图逐像素复刻\"\n    ]\n  }\n}\n",
