        "promptContent": "{\n  \"type\": \"便当格 / Bento grid 高密度模块化信息图\",\n  \"goal\": \"3:4 一图说清 Model Y 改款在续航、三电、座舱与辅助驾驶上的关注维度，带一条『适合谁』的 hero\",\n  \"canvas\": {\n    \"aspect_ratio\": \"3:4 portrait\",\n    \"background\": \"cool gray #ECEEEF\",\n    \"global_corner_radius\": \"24px\",\n    \"module_gap\": \"16px\"\n  },\n  \"header\": {\n    \"main_title\": \"Tesla Model Y 改款：续航·空间·智驾一图收齐\",\n    \"subtitle\": \"长续航 / 高性能差异、家用充电与官方标称值解读（图内为示意数字，以交付中心为准）\",\n    \"title_position\": \"top-left\"\n  },\n  \"palette\": {\n    \"primary\": \"#0F172A\",\n    \"accent\": \"#D62828\",\n    \"module_tints\": [\n      \"#DDE2E5\",\n      \"#CFE8DC\",\n      \"#C8D8F0\",\n      \"#F2E4D0\"\n    ],\n    \"rule\": \"accent 用于强调「长续航后驱」和「家充」\"\n  },\n  \"layout\": {\n    \"style\": \"asymmetric bento, hero 右下 2x2 银灰车侧\",\n    \"module_count\": \"8\",\n    \"grid\": \"左列 3 条窄条 + 右下 hero, 中区填充对比与表格式数据\",\n    \"alignment\": \"strict grid\"\n  },\n  \"modules\": [\n    {\n      \"id\": \"M1-hero\",\n      \"size\": \"large (2x2)\",\n      \"role\": \"主视觉+人群\",\n      \"content\": \"低角度 Model Y 侧影 + 一句「家第二台车 / 首台纯电 都可谈」+ 4.8/5 示意评分 + 3 个关键词: 空间 / 电耗 / OTA\"\n    },\n    {\n      \"id\": \"M2\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"CLTC 标称\",\n      \"content\": \"大数字 600+ km(示意) + 小字: CLTC, 实路受气温与脚法影响\"\n    },\n    {\n      \"id\": \"M3\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"百千米电耗\",\n      \"content\": \"13–15 kWh/100 km 带区间条, 小字: 城快 vs 高速\"\n    },\n    {\n      \"id\": \"M4\",\n      \"size\": \"medium (1x2)\",\n      \"role\": \"前备箱+后排放倒\",\n      \"content\": \"简笔容积条 + 露营模式关键词 + 1 个婴儿车示意图标\"\n    },\n    {\n      \"id\": \"M5\",\n      \"size\": \"medium (2x1)\",\n      \"role\": \"后驱长续航 vs 双电机\",\n      \"content\": \"两列对勾/叉或星级: 加速、雨雪抓地、预算; 不贬损竞品, 只陈述配置差\"\n    },\n    {\n      \"id\": \"M6\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"家充\",\n      \"content\": \"7 kW(示意) + 「谷电预约」+ 小插头图标\"\n    },\n    {\n      \"id\": \"M7\",\n      \"size\": \"medium (1x2)\",\n      \"role\": \"驾驶辅助\",\n      \"content\": \"AP/EAP 与 FSD(若购买) 分条; 用中文「辅助驾驶, 非自动驾驶」\"\n    },\n    {\n      \"id\": \"M8\",\n      \"size\": \"small (1x1)\",\n      \"role\": \"Footer\",\n      \"content\": \"微信读书式提示: 保存长图, 发家族群讨论\"\n    }\n  ],\n  \"module_internal_style\": {\n    \"padding\": \"18-22px\",\n    \"typography\": \"sans, clear hierarchy, numbers 等宽\",\n    \"rule\": \"每格 micro-title, 无空白贴纸格\",\n    \"imagery\": \"车影为简洁矢量剪影\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"价格与官方权益若出现须注明示意\",\n      \"不与其他品牌实车对比拼贴真实前脸\"\n    ],\n    \"avoid\": [\n      \"全模块等高栅格\"\n    ]\n  }\n}\n",
