        "promptContent": "{\n  \"type\": \"双列对比信息图\",\n  \"goal\": \"让读者根据习惯在两款旗舰间做理性选择, 不制造对立辱骂\",\n  \"canvas\": {\n    \"aspect_ratio\": \"3:4 portrait\",\n    \"background\": \"warm off-white #F8F6F2\",\n    \"split_line\": \"细竖线 1px #D6D0C8, 中缝上方有小型几何 VS(非涂鸦)\"\n  },\n  \"header\": {\n    \"main_title\": \"iPhone 16 Pro 还是 Galaxy S25 Ultra？7 个维度直观看懂\",\n    \"subtitle\": \"没有绝对胜负, 只有你是否在意 iOS/安卓生态与长焦风格\"\n  },\n  \"columns\": [\n    {\n      \"id\": \"left\",\n      \"name\": \"iPhone 16 Pro\",\n      \"color_theme\": \"钛灰+雾蓝, 主辅 #1C1C1E + #0A84FF\",\n      \"header_visual\": \"钛金属直边机身侧视简笔 + 灵动岛小药丸轮廓(抽象)\",\n      \"tagline\": \"iOS 生态、杜比视界录像、A 系列算力、配件丰富\"\n    },\n    {\n      \"id\": \"right\",\n      \"name\": \"Galaxy S25 Ultra\",\n      \"color_theme\": \"深墨+钛金点缀, 主辅 #111111 + #C9A962\",\n      \"header_visual\": \"方框直角屏简笔+ S Pen 小斜笔轮廓(无商标)\",\n      \"tagline\": \"安卓开放、定制主题、S Pen 批注、长焦望远玩法\"\n    }\n  ],\n  \"comparison_rows\": {\n    \"count\": \"7\",\n    \"structure\": \"中缝左图标+中文维度名, 每侧表现+星级(1-5)或对勾/横线\",\n    \"items\": [\n      \"屏幕与握持(直边 vs 略宽方屏)\",\n      \"长焦出片(偏真实 vs 高倍细节)\",\n      \"视频工作流(杜比+生态统一 vs 可拓展存储)\",\n      \"系统与多设备(与 Mac 接力 vs 与 Windows DeX 等)\",\n      \"可维修与固件(官方渠道+保值 vs 机海节奏)\",\n      \"起售价(人民币示意区间, 以电商实时为准)\",\n      \"适合的人(果粉+全家桶 / 爱折腾+安卓)\"\n    ],\n    \"marker_style\": \"1-5 星+浅底横条+少量文字(≤6字)\",\n    \"highlight_winner_per_row\": \"true, 以浅琥珀底微亮, 不一边倒\"\n  },\n  \"footer\": {\n    \"verdict\": \"要无缝办公与录视频优先 iPhone; 要大屏手写+安卓自由度优先 S25 Ultra。线下摸真机后决定。\",\n    \"winner_badge\": {\n      \"enabled\": \"false\",\n      \"label\": \"Editor's Choice\",\n      \"position\": \"left\"\n    }\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"左右列宽对称\",\n      \"每行有微型图标(镜头/屏幕/钱袋等抽象)\",\n      \"色块对比可辨但不血拼红绿\"\n    ],\n    \"avoid\": [\n      \"使用真实机模摄影抠图作商标展示\",\n      \"用侮辱性词形容任一品牌\"\n    ]\n  }\n}\n",
