        "promptContent": "{\n  \"type\": \"双列对比信息图\",\n  \"goal\": \"在膳食语境下讲清两种日常饮品的差异, 不制造焦虑\",\n  \"canvas\": {\n    \"aspect_ratio\": \"3:4 portrait\",\n    \"background\": \"cream #FAF3E8\",\n    \"split_line\": \"中缝一杯竖切, 左燕麦奶色 #D8C1A0, 右乳白 #F5F5F0, 中缝有细线+小 'VS' 圆标\"\n  },\n  \"header\": {\n    \"main_title\": \"燕麦奶 vs 牛奶: 7 个维度别盲选\",\n    \"subtitle\": \"乳糖不耐/环保/控脂/健身蛋白需求——先看表再决定囤哪一种\"\n  },\n  \"columns\": [\n    {\n      \"id\": \"left\",\n      \"name\": \"燕麦奶(强化钙维生素款)\",\n      \"color_theme\": \"燕麦金 #A67C52 + 深咖字\",\n      \"header_visual\": \"插吸管纸盒侧视简画+燕麦粒线稿\",\n      \"tagline\": \"植物、多数零乳糖(注意生产线)、咖啡友好\"\n    },\n    {\n      \"id\": \"right\",\n      \"name\": \"全脂牛乳(巴氏/高温杀菌)\",\n      \"color_theme\": \"白瓶+靛字 #1B2538\",\n      \"header_visual\": \"玻璃奶瓶弧线+小奶牛简笔\",\n      \"tagline\": \"完全蛋白、天然钙、脂溶性维生素载体\"\n    }\n  ],\n  \"comparison_rows\": {\n    \"count\": \"7\",\n    \"structure\": \"中列维度+左右对比, 可 ✓/△/– 与颜色浅底\",\n    \"items\": [\n      \"完全蛋白 PDCAAS\",\n      \"钙与 D 强化(读配料表)\",\n      \"饱和脂肪与总热量(每 250mL 示意级)\",\n      \"升糖/饱腹主观差异(不当作医学结论)\",\n      \"单价与可得性(超商常见度)\",\n      \"环境足迹(水/土/气层面定性)\",\n      \"咖啡拉花/茶拿铁适配(foam 质感)\"\n    ],\n    \"marker_style\": \"对勾+三角+短横+浅琥珀高亮'需试喝'\",\n    \"highlight_winner_per_row\": \"true, 不固定同一侧赢, 以客观符号为准\"\n  },\n  \"footer\": {\n    \"verdict\": \"补蛋白优先牛奶; 乳糖不适或要换口味时可用燕麦奶+均衡膳食。看配料表, 不迷信包装文案。\",\n    \"winner_badge\": {\n      \"enabled\": \"false\",\n      \"label\": \"\",\n      \"position\": \"left\"\n    }\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"中列维度名居中, 每行同高\",\n      \"不出现具体疾病疗效承诺\"\n    ],\n    \"avoid\": [\n      \"用极端口号否定任一饮品\"\n    ]\n  }\n}\n",
