        "id": "infographics/kpi-dashboard-infographic/1",
        "title": "Northwind AI 的 2025 年度关键指标一页",
        "categoryId": "infographics",
        "categoryLabel": "信息图",
        "categoryAccent": "#D4665A",
        "templateRef": "infographics/kpi-dashboard-infographic.md",
        "templateLabel": "Kpi Dashboard Infographic",
        "promptHint": "B2B SaaS 风暗色底，主标 ARR 与 NRR，附 pipeline、客诉、上云与员工人数，像投资人会前「一页快览」而非正式年报。所有金额与百分比为**示意**。",
        "promptContent": "{\n  \"type\": \"KPI 仪表盘信息图\",\n  \"goal\": \"把一 company's 2025 年度核心数字以 dashboard 排布, 一屏可截图至路演附录\",\n  \"canvas\": {\n    \"aspect_ratio\": \"3:4 portrait\",\n    \"background\": \"vertical gradient #0B1220 to #1E293B\",\n    \"alt_background_light\": \"N/A; this card uses dark mode\"\n  },\n  \"header\": {\n    \"main_title\": \"Northwind AI 2025 Year in Numbers\",\n    \"subtitle\": \"企业级检索与 RAG 平台 · 内部复盘稿(示意数据)\",\n    \"period\": \"2025.01 – 2025.12 (FY25)\"\n  },\n  \"palette\": {\n    \"primary_text\": \"#F1F5F9\",\n    \"accent_main\": \"#22D3EE\",\n    \"accent_secondary\": \"#A78BFA\",\n    \"accent_alert\": \"#FB7185\",\n    \"rule\": \"主数字用 accent_main, 负向/流失类用 alert 但不滥用\"\n  },\n  \"hero_metrics\": {\n    \"count\": \"3\",\n    \"rule\": \"第一行 3 张等宽大数字卡+同比小箭头(示意)\",\n    \"examples_filled\": [\n      {\n        \"value\": \"¥1.28 亿\",\n        \"label\": \"ARR(年度经常性收入, 概算)\",\n        \"delta\": \"↑ 同比 +42% (illustrative)\"\n      },\n      {\n        \"value\": \"128%\",\n        \"label\": \"净留存 NRR(概算, 大客拉动)\",\n        \"delta\": \"↑ +6 pts vs 2024\"\n      },\n      {\n        \"value\": \"312\",\n        \"label\": \"年付费企业客户(PO 口径)\",\n        \"delta\": \"↑ +58 家\"\n      }\n    ]\n  },\n  \"sub_metrics\": {\n    \"count\": \"6\",\n    \"card_types_to_use\": [\n      \"trend_line\",\n      \"donut_split\",\n      \"bar_mini\",\n      \"progress_ring\",\n      \"ranked_list\",\n      \"big_number_card\"\n    ],\n    \"rule\": \"每卡有标题+一主视觉+一行注\",\n    \"examples_filled\": [\n      {\n        \"type\": \"trend_line\",\n        \"title\": \"MRR(示意曲线)\",\n        \"delta\": \"高峰: 2025-11 大客上云集中交付\"\n      },\n      {\n        \"type\": \"donut_split\",\n        \"title\": \"行业占比\",\n        \"values\": \"金融 32% / 制造 24% / 互网 20% / 其他 24%\"\n      },\n      {\n        \"type\": \"bar_mini\",\n        \"title\": \"前三大区域(ARR)\",\n        \"items\": [\n          \"华东\",\n          \"北美西海岸\",\n          \"华北\"\n        ]\n      },\n      {\n        \"type\": \"progress_ring\",\n        \"title\": \"企业微信服务号线索 SLAs\",\n        \"value\": \"92% 24h 内响应(示意)\"\n      },\n      {\n        \"type\": \"ranked_list\",\n        \"title\": \"Top 3 新签 logo(虚构)\",\n        \"items\": [\n          \"Aurum Bank 集团\",\n          \"Lumen Motors\",\n          \"Harbor MedTech\"\n        ]\n      },\n      {\n        \"type\": \"big_number_card\",\n        \"title\": \"人均支持工单(closed)\",\n        \"value\": \"7.1 件/人/周\"\n      }\n    ]\n  },\n  \"layout\": {\n    \"structure\": \"hero 1×3 横排, 下方 2×3 卡网, 底条 footer\",\n    \"card_styling\": \"16px 圆角, 半透明 fill rgba(15,23,42,0.6), 1px #334155 边\"\n  },\n  \"footer\": {\n    \"tagline\": \"2026: 多区域部署 + 与国产算力更紧耦合(战略口号式, 非承诺)\",\n    \"credit\": \"Internal deck · 勿外传 · Northwind (fictional)\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"数字醒目\",\n      \"至少一张 trend 或 progress 表示变化\",\n      \"文中多处标注 illustrative / 概算, 不冒充审计数字\"\n    ],\n    \"avoid\": [\n      \"与真实某上市公司报表逐字雷同\",\n      \"超过 5 主色\"\n    ]\n  }\n}\n",
