        "promptContent": "{\n  \"type\": \"步骤教程信息图\",\n  \"goal\": \"7 个清晰步骤让读者在家就能安全开练, 提醒量力而行\",\n  \"canvas\": {\n    \"aspect_ratio\": \"3:4 portrait\",\n    \"background\": \"warm cream #FAF6EE, subtle paper grain 5% opacity\"\n  },\n  \"header\": {\n    \"main_title\": \"新手家庭健身 7 步入门(无器械起步)\",\n    \"subtitle\": \"每次 20–30 分钟 · 先学动作质量再谈强度\",\n    \"optional_finished_image\": \"右上角 圆角方框: 做平板支撑的剪影+绿色对勾\"\n  },\n  \"palette\": {\n    \"primary\": \"mint #6BBF90\",\n    \"secondary\": \"coral #E07A5F\",\n    \"neutral\": \"deep brown #4A3A2E\",\n    \"rule\": \"3 主色, 每步小插画同一扁平手绘风\"\n  },\n  \"layout\": {\n    \"style\": \"vertical-zigzag\",\n    \"options_explained\": {\n      \"use\": \"奇数步偏左, 偶数步偏右, 用弧箭头串联\"\n    }\n  },\n  \"steps\": {\n    \"count\": \"7\",\n    \"structure_per_step\": [\n      \"大圆形编号章\",\n      \"4–8 字加粗小标题\",\n      \"简笔人物或器材图标(瑜伽垫/椅子)\",\n      \"1–2 行说明(不超过此行数)\"\n    ],\n    \"items\": [\n      \"01 清场地: 半平米防滑垫, 移走杂物, 换运动鞋\",\n      \"02 关节热身: 肩环绕、猫牛式、半蹲画圈各 1 分钟\",\n      \"03 呼吸: 鼻吸 4 拍, 口缓呼 6 拍, 全程记呼吸不分屏\",\n      \"04 蹲起基础: 椅子坐站 12 次×2 组, 膝盖不内扣\",\n      \"05 上肢推: 墙姿俯卧撑或跪姿, 8–10 次×2 组\",\n      \"06 核心: 死虫式或侧板各 20 秒×2, 不憋气\",\n      \"07 冷身: 前屈拉伸大腿后侧、胸扩胸各 20 秒, 喝温水\"\n    ]\n  },\n  \"connectors\": {\n    \"style\": \"hand-drawn curved arrows with 2pt stroke in neutral brown\",\n    \"rule\": \"步与步间可加小小脚印\"\n  },\n  \"footer\": {\n    \"tip\": \"若胸痛、眩晕、关节锐痛, 立即停练并就医。孕妇与术后人群需遵医嘱。\",\n    \"credit\": \"家庭健身小抄·可发微信家庭群与好友\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"7 个编号风格一致\",\n      \"每步插画同风\",\n      \"无菱形决策框\"\n    ],\n    \"avoid\": [\n      \"Helvetica 纯排字\",\n      \"把步骤写成 12 行长文\"\n    ]\n  }\n}\n",
