        "promptContent": "{\n  \"type\": \"旅行路线图\",\n  \"goal\": \"生成一张京都三日古典行程的可视化路线图，作为自媒体攻略首图与打印折页封面\",\n  \"style\": \"复古手绘与水彩、米色羊皮纸底，边缘有轻微火漆纹\",\n  \"title_section\": {\n    \"title_text\": \"京都三日·庭园与古街\",\n    \"subtitle\": \"D1–D3 不走回头路的步道与机铁\"\n  },\n  \"route\": {\n    \"transport\": \"HARUKA/京都地下铁 + 公交 + 步行\",\n    \"stops\": [\n      \"D1 东山区：抵京都站 → 清水寺 → 三年坂·二年坂 → 八坂神社 → 祗园白川夕暮\",\n      \"D2 岚山与西郊：小火车嵯峨站 → 竹林小径 → 天龙寺庭园 → 渡月桥与河边茶屋 → 手打荞麦晚膳\",\n      \"D3 北山与下鸭：金阁寺镜面回游 → 北野天满宫与梅枝饼 → 下鸭糺森小径与河合神社 → 京都站茶渍饭收束\"\n    ],\n    \"line_style\": \"朱红实线示当日主线，靛青虚线示跨区机动段，圆点编号与日期同色\"\n  },\n  \"stop_illustrations\": \"每处站点配小插画：三重塔、石灯笼、竹径、月桥、金阁倒影、手制梅枝饼、糺之森下鸭流\",\n  \"side_panel\": {\n    \"enabled\": \"true\",\n    \"position\": \"右侧竖栏\",\n    \"content_type\": \"每日要点 3 天 × 2–3 条\"\n  },\n  \"side_panel_bullets\": {\n    \"D1\": [\n      \"清晨清水舞台避开人潮\",\n      \"白川通黄昏适合拍照\",\n      \"祗园餐饮需预约优先\"\n    ],\n    \"D2\": [\n      \"小火车与竹林建议预约时段\",\n      \"渡月桥风大可改室内茶屋\",\n      \"岚山豆腐与荞麦为当日主食线\"\n    ],\n    \"D3\": [\n      \"金阁以镜面池正面为必拍点\",\n      \"下鸭可顺访河合神社水签\",\n      \"返京都站可购茶渍与和菓子作手信\"\n    ]\n  },\n  \"legend\": {\n    \"items\": [\n      \"朱红实线：当日主动线\",\n      \"靛青虚线：机铁/公交\",\n      \"绿色八角：必去世界遗看点\",\n      \"小叶子：可喝茶歇脚的町家或茶屋\"\n    ]\n  },\n  \"extras\": [\n    \"和纸罗盘在左上\",\n    \"小字注：为手绘示意，非米级精确导航\"\n  ],\n  \"constraints\": {\n    \"must_keep\": [\n      \"D1→D3 顺序自洽、方位大致合理\",\n      \"每站有图与名\",\n      \"侧栏不挤压主图路线\"\n    ],\n    \"avoid\": [\n      \"一天塞入过度景点\",\n      \"路线标签压在插画之上\",\n      \"五种以上线型\"\n    ]\n  }\n}\n",
