        "promptContent": "{\n  \"type\": \"旅行路线图\",\n  \"goal\": \"生成一张美国 66 号公路经典中段七日自驾攻略主图，适合横屏封面与长图首屏\",\n  \"style\": \"做旧麻黄地图纸 + 丝网印刷式扁平色块，路边元素带美式公路漫画味\",\n  \"title_section\": {\n    \"title_text\": \"Route 66 七日·西部光与尘\",\n    \"subtitle\": \"D1–D7 小镇·峡谷·终抵太平洋日落\"\n  },\n  \"route\": {\n    \"transport\": \"SUV/房车自驾为主\",\n    \"stops\": [\n      \"D1 阿尔伯克基：老镇霓虹与热气球博物馆 → 夜宿 66 公路汽车旅馆\",\n      \"D2 石化林与彩绘沙漠：东入口入园一日纵穿，宿霍尔布鲁克汽车旅馆与恐龙像合影\",\n      \"D3 塞多纳红岩与教堂岩：短徒步与日落，夜宿红岩下民宿\",\n      \"D4 大峡谷南缘：Mather Point 与光明天使径择一短走，图萨扬补给\",\n      \"D5 胡佛水坝与米德湖观景点 → 进拉斯维加斯大道夜游收束日\",\n      \"D6 莫哈维沙漠路段：金曼老路牌博物馆 → 安博伊至巴斯托一线沙漠公路片拍摄\",\n      \"D7 圣莫尼卡码头 66 终点牌与太平洋日落，机场或市区返程\"\n    ],\n    \"line_style\": \"橘黄粗实线为主公路，白虚线示可选景观大道，星形钉示每晚住宿镇\"\n  },\n  \"stop_illustrations\": \"热气球、石化木、红岩、峡谷断崖、水坝、霓虹赌场、路牌、码头摩天轮\",\n  \"side_panel\": {\n    \"enabled\": \"true\",\n    \"position\": \"下缘横带\",\n    \"content_type\": \"每天加油/补水/看日落提示 各 1 行\"\n  },\n  \"side_panel_bullets\": {\n    \"notes\": [\n      \"沙漠段备双倍饮用水与防晒\",\n      \"大峡谷南北缘季节开放不同，图中为南缘常规线\",\n      \"拉斯住宿周末溢价高，宜提前订\",\n      \"金曼到巴斯托为长无服务段，油表半箱即加\"\n    ]\n  },\n  \"legend\": {\n    \"items\": [\n      \"橘黄实线：Route 66 主行车线（示意段）\",\n      \"蓝色波纹：可顺访水体\",\n      \"红色三角：需购票的国家公园/景点入口\",\n      \"小床：建议住宿点\"\n    ]\n  },\n  \"extras\": [\n    \"复古 66 盾形路徽角标\",\n    \"免责声明：本图为旅行灵感示意，以实时路况与公园官网为准\"\n  ],\n  \"constraints\": {\n    \"must_keep\": [\n      \"自东向西推进感清楚\",\n      \"地质景观多样但不地理穿越矛盾\",\n      \"英文地名与中文并陈可读\"\n    ],\n    \"avoid\": [\n      \"把芝加哥与 LA 同屏画成一天可达\",\n      \"路线上文字密度盖过图\",\n      \"赛博或东亚元素误插入\"\n    ]\n  }\n}\n",
