        "promptContent": "{\n  \"type\": \"角色综合设定 sheet\",\n  \"goal\": \"生成 3:4 竖版一屏的蒸汽朋克侦探主角设定，偏欧美 anime、线条干净，可直送原画拆分\",\n  \"character\": {\n    \"name\": \"Arthur Crone 阿瑟·克朗\",\n    \"concept\": \"地下城与钟塔都市的私探，前警局物证科，左臂在事故后换成黄铜蒸汽义肢\",\n    \"art_style\": \"anime 线条 + 金属材质分块明暗示意\",\n    \"gender\": \"青年男性\",\n    \"age_setting\": \"28 岁\"\n  },\n  \"sections\": {\n    \"three_view\": {\n      \"enabled\": \"true\",\n      \"items\": [\n        \"正面全身\",\n        \"侧面全身\",\n        \"背面全身\"\n      ],\n      \"annotations\": \"棕发微卷、胡茬、灰蓝眼，左臂为黄铜与皮革绑带、小型压力表在手臂外侧；长风衣后摆有齿轮镂刻暗纹不抢戏\"\n    },\n    \"expression_grid\": {\n      \"enabled\": \"true\",\n      \"count\": \"9\",\n      \"items\": [\n        \"戏谑\",\n        \"阴郁\",\n        \"暴怒\",\n        \"惊愕\",\n        \"恶心\",\n        \"温柔一次\",\n        \"推理兴奋\",\n        \"被背叛的空白\",\n        \"点烟（道具烟斗不出烟圈细节）\"\n      ]\n    },\n    \"outfit_variants\": {\n      \"enabled\": \"true\",\n      \"count\": \"3\",\n      \"items\": [\n        \"日常灰呢长风衣 + 格纹马甲 + 高帽，围巾墨绿\",\n        \"雨夜：黑色涂蜡斗篷与宽檐，义肢加防雨布套\",\n        \"化装舞会潜入：带半脸铜面具与燕尾，仍保留长风衣剪影以便识别\"\n      ]\n    },\n    \"props_and_weapons\": {\n      \"enabled\": \"true\",\n      \"items\": [\n        \"可伸缩黄铜放大镜，柄内有微型指南针\",\n        \"手杖剑，杖头为可旋转齿轮装饰\"\n      ]\n    },\n    \"color_palette\": {\n      \"enabled\": \"true\",\n      \"main\": \"烟灰、黄铜、深棕\",\n      \"accent\": \"暗酒红在内衬与领带\"\n    }\n  },\n  \"layout\": {\n    \"background\": \"浅黄灰方格，横向为主，分栏有英文与中文双标注\",\n    \"grid\": \"左列三视，右列上表情、下分衣装与道具、最下色带\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"义肢在三个视角中结构一致、齿比不乱\",\n      \"九格为同一脸骨相\",\n      \"雾与煤烟氛围不在设定稿中体现，只在线稿细节暗示工业城市\"\n    ],\n    \"avoid\": [\n      \"可识别伦敦地标照片拼贴\",\n      \"可辨识福尔摩斯版权造型逐帧复刻\",\n      \"三视高度漂移\"\n    ]\n  }\n}\n",
