        "promptContent": "{\n  \"type\": \"媒体大片级创始人肖像\",\n  \"goal\": \"生成 3:4 竖版可用于科技财经媒体专题开篇或长文头图的创始人环境人像，人物可辨识为美国企业家 Elon Musk 的公众形象，气质硬朗有叙事，不戏谑、不漫展风\",\n  \"subject\": {\n    \"identity\": \"航天与智能电动车领域连续创业者、上市公司高管\",\n    \"gender\": \"美国男性\",\n    \"age_range\": \"45-60 岁\",\n    \"appearance\": \"短发或略卷短发，可留轻短髭，肤色自然偏暖但在冷调环境中略压饱和\",\n    \"outfit\": \"黑或炭灰 T 恤或高领针织、外搭未扣的深色短夹克，无可见品牌大 logo\"\n  },\n  \"composition\": {\n    \"shot\": \"腰上环境人像，人物占垂直方向约 60%\",\n    \"framing\": \"人物在画面左 1/3 立柱旁，右 2/3 为虚化的落地窗外城市夜景或厂房轮廓的侧影\",\n    \"title_safe_area\": \"右上 25% 区域保持干净深色或低纹理，为中文标题与英文副题预留；人物视线朝右可引导阅读\"\n  },\n  \"environment\": {\n    \"location\": \"高天花板现代办公空间，地面反光弱，远处有长桌与单椅的剪影，不仿任何知名总部可识别内装\",\n    \"depth\": \"f/2.0 左右浅景深，窗格线条柔化为几何光带\"\n  },\n  \"lighting\": {\n    \"style\": \"大窗侧光 + 弱室内顶光，整体中低调\",\n    \"key_light\": \"自画面左侧大窗入射的冷白日光或蓝白城市反射光，人物面颊主亮区清晰\",\n    \"fill_light\": \"对侧深灰墙反射约 0.2 比补光，保留夹克纹理\",\n    \"color_temp\": \"主光略冷 6000-6500K，肤色在后期允许微提暖 200K 仅到自然\"\n  },\n  \"expression\": {\n    \"mood\": \"沉思、带一点向未来的眺望感，嘴角中性略紧\",\n    \"gaze\": \"视线略向画面外右上方，与标题安全区同向，不看镜头正中央\"\n  },\n  \"style\": {\n    \"rendering\": \"杂志级人像锐度、印刷可放大\",\n    \"tone\": \"暗部不糊死，高光窗沿略滚降，有轻微胶片颗粒 8-12% 不噪点化皮肤\",\n    \"color_palette\": \"冷灰 + 墨黑 + 受光侧肤色的暖中调\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"光线方向自洽，窗与面部转折阴影一致\",\n      \"右上与刊头阅读路径无杂乱道具穿帮\",\n      \"不叠企业商标与车 logo\"\n    ],\n    \"avoid\": [\n      \"红蓝霓虹赛博\",\n      \"强烈轮廓灯造成舞台妆感\",\n      \"背景中可读的 SpaceX 或 Tesla 实标\"\n    ]\n  }\n}\n",
