        "promptContent": "{\n  \"type\": \"媒体大片级创始人肖像\",\n  \"goal\": \"生成 4:5 竖版人物专访封面气质图，以 Sam Altman 公众可联想的外貌为线索：清瘦、短发、温和表情，着简约深色服装，不卡通化，用于文化与科技交叉刊物或深度报道头图\",\n  \"subject\": {\n    \"identity\": \"人工智能与创业投资领域美国企业家、公共讲者\",\n    \"gender\": \"美国男性\",\n    \"age_range\": \"35-45 岁\",\n    \"appearance\": \"短发、清爽，肤色较浅，可轻微胡茬，眼镜可选\",\n    \"outfit\": \"墨绿或深棕羊绒圆领衫外搭无结构炭灰单西，不系领带\"\n  },\n  \"composition\": {\n    \"shot\": \"胸到腰半身，肩线水平\",\n    \"framing\": \"人物略靠右，左侧 1/3 为暗书墙与一道窄暖光带，为竖排大引语预留\",\n    \"title_safe_area\": \"左上交叠区域与左中竖长条为白字可压暗底处\"\n  },\n  \"environment\": {\n    \"location\": \"有整墙书籍与少量抽象画的室内空间，景深浅，书脊不辨读\",\n    \"depth\": \"前景无遮挡物，书墙退后两米外虚化\"\n  },\n  \"lighting\": {\n    \"style\": \"单一大柔光自左前 30° 扫过面部与单西肩线\",\n    \"key_light\": \"暖日光灯或窗光 4200-4600K，面部三角光干净\",\n    \"fill_light\": \"对侧 1:3 弱泡沫板反\",\n    \"color_temp\": \"整体略暖、心理距离亲和\"\n  },\n  \"expression\": {\n    \"mood\": \"平静、倾听感，略带笑意的克制\",\n    \"gaze\": \"正视镜头下沿三分之一处，略「穿过镜头」的访谈感\"\n  },\n  \"style\": {\n    \"rendering\": \"高分辨率、噪点低，印刷杂志可用\",\n    \"tone\": \"对比中等，不压成低长调黑白\",\n    \"color_palette\": \"书墙暖木棕 + 服装冷灰 + 肤色的自然中间调\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"书墙不出现可辨真书封面与政治口号\",\n      \"左区留白不碎、不断裂\",\n      \"无 OpenAI 字标在画面内\"\n    ],\n    \"avoid\": [\n      \"过锐导致塑料肤\",\n      \"强逆光剪影丢失眼神\",\n      \"与人物公开照片逐像素复刻\"\n    ]\n  }\n}\n",
