        "promptContent": "{\n  \"type\": \"VTuber Debut 个人资料卡\",\n  \"goal\": \"生成 9:16 竖版出道资料卡，可直接作为微博超话首图、B 站动态首图、微信视频号「账号资料页」主视觉参考\",\n  \"character\": {\n    \"name\": \"樱下川 初日\",\n    \"style\": \"日系 TV anime 赛璐璐 + 赛璐璐阴影两层\",\n    \"gender\": \"少女\",\n    \"age_setting\": \"18 岁（设定为虚拟艺龄）\",\n    \"appearance\": \"粉樱双马尾、薄荷绿眼瞳、露肩改良短振袖，腰封与小腿袜有樱花瓣刺绣，耳边佩戴无线麦造型小道具\",\n    \"pose\": \"半身立绘，身体微 15° 侧向、一手轻提袖角，微笑有亲和力，一手伸出像邀请进直播间\"\n  },\n  \"color_theme\": {\n    \"main_color\": \"樱粉 + 芽绿\",\n    \"accent_color\": \"金线勾边小面积\"\n  },\n  \"debut_info\": {\n    \"debut_date\": \"2026.5.10\",\n    \"platform\": \"Bilibili 直播 · 微信视频号 同步初配信\",\n    \"tags\": \"#初配信 #国V #春樱组 #晚九点见\",\n    \"agency\": \"春鸣社 VirtuaLink\"\n  },\n  \"background\": {\n    \"type\": \"黄昏时分河边垂樱与远山城剪影，天顶渐变为浅紫到淡橙\",\n    \"fx\": \"缓缓飘落的发光樱瓣 + 少许可控粒子、镜头前景一层柔焦花瓣虚化\"\n  },\n  \"layout\": {\n    \"character_position\": \"画面右下偏中，脚下留 12% 给社标与条型码位\",\n    \"info_block_position\": \"左上竖排：艺名、首播时间、三行小字 tag，字色深褐或深灰、白描边 1px\",\n    \"logo_position\": \"右下小「春鸣社」原创几何字与图形，面积不超过画面 4%\"\n  },\n  \"aspect_ratio\": \"9:16\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"艺名、首播日、三平台字段清晰可读，不被头发大面积遮挡\",\n      \"主色与服色、背景樱花一致\",\n      \"脸部无文字叠印\"\n    ],\n    \"avoid\": [\n      \"使用 Bilibili 小电视等受保护商标的精确形\",\n      \"字体系超过三种\",\n      \"背景过曝吞掉线稿\"\n    ]\n  }\n}\n",
