        "promptContent": "{\n  \"type\": \"VTuber 直播预览缩略图\",\n  \"goal\": \"生成 16:9 强点击的直播缩略图，主标题在画面安全区内，小字不挤在 9:16 切图危险区，适配微信与横屏首帧\",\n  \"aspect_ratio\": \"16:9\",\n  \"character\": {\n    \"name\": \"铁犀 深潜\",\n    \"style\": \"厚涂 anime + 金属材质高光\",\n    \"gender\": \"青年男性虚拟形象\",\n    \"age_setting\": \"22 岁\",\n    \"appearance\": \"深褐短发、金瞳，半脸复古呼吸面罩、肩甲外露液压管，上身战术背心内搭黑色高领，胸前有自制发光小屏幕显示波形\",\n    \"pose\": \"上半身占画面右半，左手握拳在胸前、右手前指像喊麦，大表情眉毛高挑、嘴大开笑\"\n  },\n  \"color_theme\": {\n    \"main_color\": \"铁锈铜绿 + 海军蓝\",\n    \"accent_color\": \"荧光橙在管线与灯条，面积 ≤8%\"\n  },\n  \"debut_info\": {\n    \"debut_date\": \"2026.6.1\",\n    \"platform\": \"Bilibili 首播 · 微信视频号 回放与切片首发\",\n    \"tags\": \"#机甲 #杂谈 #开坑独立游戏\",\n    \"agency\": \"深潜工造 Project Sublink\"\n  },\n  \"background\": {\n    \"type\": \"废弃船坞雨天夜景，远灯点点，不仿真实军港可辨读标识\",\n    \"fx\": \"雨丝斜向、金属表面雨水高光、远处偶发小爆炸橙光不喧宾\"\n  },\n  \"title_overlay\": {\n    \"main\": \"首航夜：在废港里开麦\",\n    \"sub\": \"21:30 铁犀深潜 B站·微信视频号 同步\"\n  },\n  \"layout\": {\n    \"character_position\": \"右 55%，左 45% 为标题与副行\",\n    \"info_block_position\": \"左上三行，左下为平台提示小字，远离画面下缘 6% 安全区\",\n    \"logo_position\": \"左下小 project 标\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"主标题在 9:16 中裁时仍完全可见（主体偏右、文偏左）\",\n      \"面罩与管线的结构线清晰、不断裂\",\n      \"出现「微信」字样时与 B 站并列、不用英文替代\"\n    ],\n    \"avoid\": [\n      \"可识别军徽、真实国别旗帜\",\n      \"全屏大颗粒噪点挡脸\",\n      \"小字用荧光绿底黑字等不可读方案\"\n    ]\n  }\n}\n",
