        "promptContent": "{\n  \"type\": \"Campaign Key Visual 主视觉系统\",\n  \"goal\": \"生成空间计算设备迭代季的传播主视觉与比例衍生示意合图，调性静、少即是多，不虚构具体未发布硬件型号编号\",\n  \"campaign\": {\n    \"name\": \"Apple Vision 空间计算 下一章 2026\",\n    \"claim\": \"把系统界面，从屏幕抬到空间\",\n    \"duration\": \"2026.3.1 - 2026.4.15\"\n  },\n  \"visual_system\": {\n    \"color_palette\": \"深空银 + 白雾 + 青紫边缘光\",\n    \"anchor_visual\": {\n      \"description\": \"一台造型简洁的头戴显示设备侧面剪影浮于半空中，面罩为连续曲面玻璃、无品牌刻印细读；周缘环绕轻盈的半透明多窗口信息层，以抽象几何与地图线条暗示空间 UI；主视觉不展示真实 watchOS 界面截图\",\n      \"composition\": \"设备略偏左，右半幅留给中英文 claim 与光晕\"\n    },\n    \"graphic_motif\": \"同心细圆与缓慢移动的粒子，象征空间锚点，重复出现但透明度低\"\n  },\n  \"claim_typography\": {\n    \"font_style\": \"大字号中文黑体 + 小一号英文全大写无衬线\",\n    \"color\": \"近白字 + 弱灰辅助小字\"\n  },\n  \"derivative_layouts\": {\n    \"enabled\": \"true\",\n    \"items\": [\n      \"1:1 以设备面罩为圆心作对称裁切\",\n      \"9:16 人物手伸入画框的构图（不露脸，只展示手与设备关系）\",\n      \"16:9 大横幅以地平线与设备剪影形成「地面—天空」比\"\n    ],\n    \"rule\": \"主图下缘三个线框小稿，分别写 1:1 / 9:16 / 16:9，角落苹果叶状抽象符号为示意非官方\"\n  },\n  \"logo_placement\": {\n    \"position\": \"右下角极简几何叶形与细字，仅为风格暗示\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"同一光照与雾效贯穿四格\",\n      \"claim 不被裁到安全区外\",\n      \"不使用真实发布会舞台照片拼贴\"\n    ],\n    \"avoid\": [\n      \"出现 Health app 等可识别 iOS 真实截图\",\n      \"设备上贴多枚贴纸与赞助标\",\n      \"紫绿霓虹赛博朋克与品牌克制气质冲突\"\n    ]\n  }\n}\n",
