        "promptContent": "{\n  \"type\": \"杂志封面\",\n  \"goal\": \"生成就时装片气质的 4:5 或 3:4 竖版封面，主标题中文、装饰英文，主视觉为全身或膝上像\",\n  \"publication\": {\n    \"name\": \"VOGUE 服饰与美容\",\n    \"tagline\": \"时尚 · 电影 · 音乐\",\n    \"issue\": \"2026 年 3 月号 / 开季号\"\n  },\n  \"aspect_ratio\": \"4:5\",\n  \"main_visual\": {\n    \"type\": \"人物时装肖像\",\n    \"description\": \"一位 30 岁左右的虚构金棕长卷发女性主体（脸型鹅蛋、淡橄榄肤色、灰蓝眼瞳），膝上像，浅香槟色缎面连衣裙，长卷发松垂一侧，手轻提裙摆，目光略带叙事感望向画外，背景为无接缝暖灰棚拍，地面淡反射\",\n    \"composition\": \"人物略偏左，右三分之一留给竖排大标题与刊名，头顶上方留天头\"\n  },\n  \"title_block\": {\n    \"main_title\": \"重返舞台之前\",\n    \"main_title_style\": \"竖排高对比衬线，字距略松，在人物右肩旁自下而上或自上而下依构图择一，局部叠在轻纱上时降低不透明度 15%\",\n    \"kicker\": \"独家专访\"\n  },\n  \"side_teasers\": {\n    \"count\": \"4\",\n    \"items\": [\n      \"知名脱口秀主持人对话代际创伤与愈合\",\n      \"春装：从秀场到城市街景的十六套翻译\",\n      \"前白宫书单里反复出现的五位作家\",\n      \"美容：以油养肤在本季的新配方主义\"\n    ],\n    \"position\": \"左侧竖列窄条小字，或底部两栏英文导读\"\n  },\n  \"color_palette\": \"米白天头 + 暖金标题 + 人物肤色自然偏粉\",\n  \"barcode\": {\n    \"enabled\": \"true\",\n    \"position\": \"左下角或右下角不压人物足尖\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"主标题与人物衣物边缘对比充足\",\n      \"全刊中文导读无错别字，英文为标题级短语非长段\",\n      \"整体留白 ≥ 15%，呼吸感与奢侈品气质一致\"\n    ],\n    \"avoid\": [\n      \"多品牌化妆品拼贴角标\",\n      \"与真实某一期 VOGUE 逐字或逐张复刻\",\n      \"背景出现可辨城市地标准拍\",\n      \"刻意贴近任何具体真实公众人物的肖像细节\"\n    ]\n  }\n}\n",
