        "promptContent": "{\n  \"type\": \"组织 / 团队结构图\",\n  \"goal\": \"生成一张金字塔 + 关系网结合的企业卡通版架构海报，3:4，标题幽默但不侮辱人物\",\n  \"ip\": {\n    \"name\": \"「云端理事会」虚构圆桌：AI 与消费硬件峰层对话\",\n    \"tone\": \"现代企业海报 + Q 版头像 + 轻漫画勾线\"\n  },\n  \"characters\": {\n    \"count\": \"8\",\n    \"user_list\": \"Sam Altman、Jensen Huang、Sundar Pichai、Tim Cook、Elon Musk、Mark Zuckerberg、Bill Gates、Warren Buffett\",\n    \"card_design\": {\n      \"components\": [\n        \"Q 版大头\",\n        \"仅姓氏英文大写+中文职务玩笑标签\"\n      ],\n      \"shape\": \"圆角方形\"\n    }\n  },\n  \"composition\": {\n    \"structure\": \"金字塔：顶层单卡「智囊会」抽象图标，中上层 Sam Altman 与 Sundar Pichai 并列，中下层 Jensen Huang 与 Elon Musk 分两侧，底排 Tim Cook、Mark Zuckerberg、Bill Gates、Warren Buffett 呈基座分布\",\n    \"hierarchy\": \"越靠上卡略大，表示议题权重而非真实职级\"\n  },\n  \"relationships\": {\n    \"types\": [\n      {\n        \"name\": \"算力与模型合作\",\n        \"color\": \"电青\",\n        \"line\": \"实线\"\n      },\n      {\n        \"name\": \"消费硬件生态\",\n        \"color\": \"银灰\",\n        \"line\": \"虚线\"\n      },\n      {\n        \"name\": \"公开市场竞争\",\n        \"color\": \"品红\",\n        \"line\": \"锯齿线\"\n      },\n      {\n        \"name\": \"行业倡议 / 非盈利线\",\n        \"color\": \"松绿\",\n        \"line\": \"粗实线\"\n      }\n    ],\n    \"annotation_rule\": \"线旁用中英混合短词，如「API」「OEM」\"\n  },\n  \"title_block\": {\n    \"main_title\": \"云端理事会：一张图装不下的想象力\",\n    \"subtitle\": \"纯属创意拼图，与真实公司汇报关系无关\",\n    \"position\": \"顶部\"\n  },\n  \"legend\": {\n    \"enabled\": \"true\",\n    \"position\": \"左下角\"\n  },\n  \"style\": {\n    \"art_style\": \"扁平常用 UI 色 + 柔投影 + Q 版头像\",\n    \"color_palette\": \"浅灰底、主色不超过 5 个明确 HEX 块面\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"每个头像为可辨 Q 版风格，不写实摄影\",\n      \"注记合法合规，不暗示未经证实丑闻\",\n      \"线不穿过头像中央\"\n    ],\n    \"avoid\": [\n      \"信息过载，单卡文字过多\",\n      \"真实公司财报或股价数字\"\n    ]\n  }\n}\n",
