        "promptContent": "{\n  \"type\": \"单页多分镜漫画\",\n  \"goal\": \"生成一张完整的单页漫画，含 6 个不规则分镜，叙事为轻松校园误会\",\n  \"story\": {\n    \"summary\": \"女生在走廊被风掀起裙摆一角，错以为身后男生在拍照，其实对方只是在回微信。\",\n    \"main_character\": \"齐肩短发女生，水手服，书包侧袋露出画筒，表情丰富。\",\n    \"supporting\": \"瘦高男生，连帽衫，单手举手机，屏幕朝自己。\"\n  },\n  \"style\": {\n    \"art_style\": \"日式黑白少女漫画 + 排线网点 + 强黑白对比\",\n    \"tone\": \"轻快、略带尴尬与好笑\",\n    \"color\": \"黑白 + 灰阶\"\n  },\n  \"page_layout\": {\n    \"panel_count\": \"6\",\n    \"reading_direction\": \"日式：从右到左、从上到下\",\n    \"panels\": [\n      {\n        \"id\": 1,\n        \"size\": \"大格 右上到跨中\",\n        \"scene\": \"风吹走廊窗帘，女生按住裙摆，回眸警惕\",\n        \"text\": \"女生：你刚才举手机了？\"\n      },\n      {\n        \"id\": 2,\n        \"size\": \"中格 右下\",\n        \"scene\": \"男生愣住，手机亮着微信聊天界面小缩略图可辨\",\n        \"text\": \"男生：我在回组长……\"\n      },\n      {\n        \"id\": 3,\n        \"size\": \"小格 中左\",\n        \"scene\": \"女生瞳孔特写，脑补闪光灯（用夸张竖线）\",\n        \"text\": \"心声：不对，他在狡辩！\"\n      },\n      {\n        \"id\": 4,\n        \"size\": \"中格 左中\",\n        \"scene\": \"女生一步上前，手指几乎戳到手机壳\",\n        \"text\": \"女生：把相册打开。\"\n      },\n      {\n        \"id\": 5,\n        \"size\": \"中格 左下\",\n        \"scene\": \"男生无奈滑屏，满屏是课程群和文件传输助手\",\n        \"text\": \"男生：真没有。你看。\"\n      },\n      {\n        \"id\": 6,\n        \"size\": \"大格 最下全宽\",\n        \"scene\": \"两人并排靠在窗边，女生小声道歉，男生挠头，窗外樱花瓣飘过\",\n        \"text\": \"旁白：风太大，人也会想太多。\"\n      }\n    ]\n  },\n  \"dialogue_design\": {\n    \"balloon_style\": \"白底 + 黑描边 + 尖角\",\n    \"narration_box\": \"矩形灰底 + 细黑边\",\n    \"thought_balloon\": \"云形虚线\",\n    \"font_style\": \"无衬线漫画体\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"6 格大小有对比\",\n      \"主角同一人、制服一致\",\n      \"微信仅作小道具，不喧宾夺主\"\n    ],\n    \"avoid\": [\n      \"分镜全等大\",\n      \"全页无网点层次\",\n      \"阅读顺序难辨认\"\n    ]\n  }\n}\n",
