        "promptContent": "{\n  \"type\": \"食谱步骤图\",\n  \"goal\": \"生成一张可作为公众号 / 小红书 / 家庭食谱内页的番茄炒蛋步骤图\",\n  \"recipe\": {\n    \"name\": \"番茄炒蛋\",\n    \"subtitle\": \"5 分钟家常版\",\n    \"servings\": \"2 人份\",\n    \"time\": \"备料 2 分钟 + 烹制 3 分钟\"\n  },\n  \"ingredients\": {\n    \"enabled\": \"true\",\n    \"position\": \"顶部右侧\",\n    \"items\": [\n      \"番茄 2 个（约 300g）\",\n      \"鸡蛋 3 个\",\n      \"葱花 1 小把\",\n      \"盐 3g、糖 2g、植物油 20ml\"\n    ],\n    \"design\": \"每项左侧配迷你图标：番茄圆、蛋、葱、盐罐、油滴\"\n  },\n  \"steps\": {\n    \"count\": \"5\",\n    \"items\": [\n      {\n        \"id\": 1,\n        \"scene\": \"番茄切滚刀块，鸡蛋加一撮盐打散至起小泡\"\n      },\n      {\n        \"id\": 2,\n        \"scene\": \"炒锅中火油烧至微冒烟，倒蛋液，用筷子划散至半凝固盛出\"\n      },\n      {\n        \"id\": 3,\n        \"scene\": \"补少许油，下番茄中大火煸至出沙、边缘微化\"\n      },\n      {\n        \"id\": 4,\n        \"scene\": \"倒回鸡蛋，加盐、少糖，快速翻匀 10 秒\"\n      },\n      {\n        \"id\": 5,\n        \"scene\": \"关火撒葱花，装盘淋少许锅气汁\"\n      }\n    ],\n    \"step_block_style\": \"圆形编号 + 侧剖插图 + 一句说明\"\n  },\n  \"final_dish\": {\n    \"enabled\": \"true\",\n    \"position\": \"底部居中大图\"\n  },\n  \"style\": {\n    \"art_style\": \"手绘水彩 + 淡米色水彩纸纹 + 细铅笔线稿感\",\n    \"color_palette\": \"番茄红、蛋黄、葱绿、米白\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"1–5 编号连续、无跳号\",\n      \"每步说明不超过 15 字\",\n      \"食材列表与步骤动作对应\",\n      \"成品区饱和略高、吸引食欲\"\n    ],\n    \"avoid\": [\n      \"单步出现与中餐无关的奇异设备\",\n      \"荧光蓝等反食物色为大面积主色\"\n    ]\n  }\n}\n",
