        "promptContent": "{\n  \"type\": \"食谱步骤图\",\n  \"goal\": \"生成一张拿铁制作流程图，将配方嵌入步骤信息区，强调在家可复制\",\n  \"recipe\": {\n    \"name\": \"意式拿铁\",\n    \"subtitle\": \"双份浓缩 + 薄奶泡\",\n    \"servings\": \"1 杯（约 240ml）\",\n    \"time\": \"8 分钟\"\n  },\n  \"ingredients\": {\n    \"enabled\": \"true\",\n    \"position\": \"顶部左侧通栏\",\n    \"items\": [\n      \"中深烘咖啡豆 18g\",\n      \"全脂牛奶 200ml\",\n      \"可选：焦糖 5ml 或肉桂粉一撮\"\n    ],\n    \"design\": \"扁平图标 + 克数\"\n  },\n  \"steps\": {\n    \"count\": \"6\",\n    \"items\": [\n      {\n        \"id\": 1,\n        \"scene\": \"意式手磨或电磨意式细度，布粉压粉填平粉碗\"\n      },\n      {\n        \"id\": 2,\n        \"scene\": \"92℃ 水，25–30 秒萃取约 36g 双份浓缩入宽口杯\"\n      },\n      {\n        \"id\": 3,\n        \"scene\": \"冷牛奶倒入拉花缸，蒸汽棒埋入液面下打绵至 60℃\"\n      },\n      {\n        \"id\": 4,\n        \"scene\": \"震缸、画圈融合奶泡，倒入浓缩液中心定点\"\n      },\n      {\n        \"id\": 5,\n        \"scene\": \"抬高缸嘴收尾拉一颗简化白色心形\"\n      },\n      {\n        \"id\": 6,\n        \"scene\": \"杯沿揩净，放杯垫出品\"\n      }\n    ],\n    \"step_block_style\": \"左编号右插图，右侧同一行 1 条说明\"\n  },\n  \"final_dish\": {\n    \"enabled\": \"true\",\n    \"position\": \"底部右侧成品特写，带薄奶泡光泽\"\n  },\n  \"style\": {\n    \"art_style\": \"扁平矢量 + 深咖与奶白大色块 + 轻微颗粒\",\n    \"color_palette\": \"深焙棕、陶瓷白、蒸汽灰蓝\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"6 步顺序符合咖啡师常规操作\",\n      \"温度与量词不互相矛盾\",\n      \"成品图能看清咖啡油脂与奶泡对比\"\n    ],\n    \"avoid\": [\n      \"单步超过 15 个汉字\",\n      \"随意替换为速溶咖啡步骤（与标题不符时）\"\n    ]\n  }\n}\n",
