        "promptContent": "{\n  \"type\": \"工程感流程图 / 决策图\",\n  \"goal\": \"生成 3:4 竖版暗色位图，展示注册全链路及风控分支\",\n  \"canvas\": {\n    \"aspect_ratio\": \"3:4\",\n    \"background\": \"deep slate #0F172A with subtle 1px grid #1E293B at 32px spacing\",\n    \"outer_padding\": \"60px\"\n  },\n  \"title_strip\": {\n    \"title\": \"用户注册与激活流程\",\n    \"subtitle\": \"短信 OTP + 邮箱 + 设备风控\",\n    \"position\": \"top-left, JetBrains Mono\"\n  },\n  \"flow_direction\": \"top-to-bottom\",\n  \"shape_legend\": \"与模板一致（起止圆/药丸、过程矩形、决策菱形、IO 平行四边形、子流程双框）\",\n  \"nodes\": {\n    \"count\": \"15\",\n    \"items\": [\n      {\n        \"id\": \"S\",\n        \"type\": \"start_end\",\n        \"label\": \"开始\"\n      },\n      {\n        \"id\": \"I1\",\n        \"type\": \"io\",\n        \"label\": \"用户提交 手机号+密码+设备指纹 device_id\"\n      },\n      {\n        \"id\": \"P1\",\n        \"type\": \"process\",\n        \"label\": \"校验 E.164 与密码强度 (zxcvbn≥3)\"\n      },\n      {\n        \"id\": \"D1\",\n        \"type\": \"decision\",\n        \"label\": \"手机号已注册？\"\n      },\n      {\n        \"id\": \"P2\",\n        \"type\": \"process\",\n        \"label\": \"返回 409 并提示 微信 一键登录\"\n      },\n      {\n        \"id\": \"P3\",\n        \"type\": \"process\",\n        \"label\": \"创建 users 行 status= PENDING\"\n      },\n      {\n        \"id\": \"D2\",\n        \"type\": \"decision\",\n        \"label\": \"风控分数 risk_score < 0.4？\"\n      },\n      {\n        \"id\": \"SP1\",\n        \"type\": \"subprocess\",\n        \"label\": \"子流程: 进人工 queue_id 风控复核\"\n      },\n      {\n        \"id\": \"P4\",\n        \"type\": \"process\",\n        \"label\": \"短信网关发送 6 位 OTP (5min TTL)\"\n      },\n      {\n        \"id\": \"D3\",\n        \"type\": \"decision\",\n        \"label\": \"OTP 与 Redis 中 digest 一致？\"\n      },\n      {\n        \"id\": \"P5\",\n        \"type\": \"process\",\n        \"label\": \"发验证邮件 含 token (HKDF-SHA256)\"\n      },\n      {\n        \"id\": \"D4\",\n        \"type\": \"decision\",\n        \"label\": \"24h 内点击验证链接？\"\n      },\n      {\n        \"id\": \"P6\",\n        \"type\": \"process\",\n        \"label\": \"status= VERIFIED, email_verified_at 写入\"\n      },\n      {\n        \"id\": \"P7\",\n        \"type\": \"process\",\n        \"label\": \"删除过期 token+软删未激活\"\n      },\n      {\n        \"id\": \"E\",\n        \"type\": \"start_end\",\n        \"label\": \"结束\"\n      }\n    ]\n  },\n  \"edges\": {\n    \"items\": [\n      {\n        \"from\": \"S\",\n        \"to\": \"I1\"\n      },\n      {\n        \"from\": \"I1\",\n        \"to\": \"P1\"\n      },\n      {\n        \"from\": \"P1\",\n        \"to\": \"D1\"\n      },\n      {\n        \"from\": \"D1\",\n        \"to\": \"P2\",\n        \"label\": \"Yes\"\n      },\n      {\n        \"from\": \"D1\",\n        \"to\": \"P3\",\n        \"label\": \"No\"\n      },\n      {\n        \"from\": \"P2\",\n        \"to\": \"E\"\n      },\n      {\n        \"from\": \"P3\",\n        \"to\": \"D2\"\n      },\n      {\n        \"from\": \"D2\",\n        \"to\": \"SP1\",\n        \"label\": \"No\"\n      },\n      {\n        \"from\": \"D2\",\n        \"to\": \"P4\",\n        \"label\": \"Yes\"\n      },\n      {\n        \"from\": \"SP1\",\n        \"to\": \"E\"\n      },\n      {\n        \"from\": \"P4\",\n        \"to\": \"D3\"\n      },\n      {\n        \"from\": \"D3\",\n        \"to\": \"P5\",\n        \"label\": \"Yes\"\n      },\n      {\n        \"from\": \"D3\",\n        \"to\": \"E\",\n        \"label\": \"No\"\n      },\n      {\n        \"from\": \"P5\",\n        \"to\": \"D4\"\n      },\n      {\n        \"from\": \"D4\",\n        \"to\": \"P6\",\n        \"label\": \"Yes\"\n      },\n      {\n        \"from\": \"D4\",\n        \"to\": \"P7\",\n        \"label\": \"No\"\n      },\n      {\n        \"from\": \"P6\",\n        \"to\": \"E\"\n      },\n      {\n        \"from\": \"P7\",\n        \"to\": \"E\"\n      }\n    ],\n    \"edge_style\": {\n      \"default\": \"slate 1.5px + 三角箭头\",\n      \"yes_branch\": \"emerald #34D399\",\n      \"no_branch\": \"slate\",\n      \"exception_branch\": {\n        \"enabled\": \"true\",\n        \"style\": \"dashed rose\",\n        \"use_on\": \"D3=No 快速退出\"\n      }\n    }\n  },\n  \"swim_lanes\": {\n    \"enabled\": \"false\"\n  },\n  \"legend\": {\n    \"enabled\": true,\n    \"position\": \"bottom-right\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"决策必有 Yes/No 或等义标签\",\n      \"子流程为双框\"\n    ],\n    \"avoid\": [\n      \">15 节点\"\n    ]\n  }\n}\n",
