        "promptHint": "总部与两地分支经 MPLS+Internet 双上行（Active/Active）、hub 级防火墙、控制器纳管、以及一条至 VPC 的 VPN/Direct Connect 汇流，是零售或制造总部「一张网管门店」HLD 常见形态。",
        "promptContent": "{\n  \"type\": \"工程感网络拓扑图\",\n  \"goal\": \"生成一张企业级 SD-WAN 逻辑拓扑位图，含 Internet、MPLS、各站点 CPE、中心汇聚防火墙与 orchestrator、以及上云专线的加密隧道（IPsec/BGP 标注），大框表示站点与安全域\",\n  \"canvas\": {\n    \"aspect_ratio\": \"16:9\",\n    \"background\": \"deep slate #0F172A with subtle 1px grid #1E293B at 32px spacing\",\n    \"outer_padding\": \"60px\"\n  },\n  \"title_strip\": {\n    \"title\": \"Aurora Retail SD-WAN 总部-分支-云 一体拓扑\",\n    \"subtitle\": \"MPLS + 双互联网 + 云专线 · BGP ASN 65001\",\n    \"position\": \"top-left, JetBrains Mono / SF Mono, light gray\"\n  },\n  \"device_glyphs\": {\n    \"rule\": \"router=菱形内叉、firewall=砖墙、cloud=简笔云+文字 CPE/ctrl\",\n    \"types\": [\n      {\n        \"type\": \"router\",\n        \"glyph\": \"diamond with X\",\n        \"color\": \"amber #FBBF24\"\n      },\n      {\n        \"type\": \"firewall\",\n        \"glyph\": \"brick wall\",\n        \"color\": \"rose #FB7185\"\n      },\n      {\n        \"type\": \"switch\",\n        \"glyph\": \"rect multiple bottom ports\",\n        \"color\": \"amber #FBBF24\"\n      },\n      {\n        \"type\": \"server\",\n        \"glyph\": \"rack 3-4 槽\",\n        \"color\": \"emerald #34D399\"\n      },\n      {\n        \"type\": \"cloud_service\",\n        \"glyph\": \"cloud with text\",\n        \"color\": \"cyan #22D3EE\"\n      },\n      {\n        \"type\": \"user\",\n        \"glyph\": \"stick figure\",\n        \"color\": \"cyan #22D3EE\"\n      }\n    ]\n  },\n  \"zones\": {\n    \"count\": 4,\n    \"items\": [\n      {\n        \"id\": \"Z1\",\n        \"label\": \"总部 DC 核心 · VLAN10/20 汇聚\",\n        \"color_border\": \"amber #FBBF24 dashed\",\n        \"cidr\": \"172.20.0.0/16\"\n      },\n      {\n        \"id\": \"Z2\",\n        \"label\": \"上海门店 · CPE-3000\",\n        \"color_border\": \"blue #60A5FA dashed\",\n        \"cidr\": \"10.30.0.0/20\"\n      },\n      {\n        \"id\": \"Z3\",\n        \"label\": \"深圳 R&D 实验室\",\n        \"color_border\": \"emerald #34D399 dashed\",\n        \"cidr\": \"10.40.0.0/20\"\n      },\n      {\n        \"id\": \"Z4\",\n        \"label\": \"云托管区 (VPN/DX 落地)\",\n        \"color_border\": \"violet #A78BFA dashed\",\n        \"cidr\": \"10.200.0.0/20\"\n      }\n    ]\n  },\n  \"nodes\": {\n    \"items\": [\n      {\n        \"id\": \"N1\",\n        \"type\": \"router\",\n        \"label\": \"HQ 边界路由器 A\\\\n(BGP 65001)\",\n        \"zone\": \"Z1\"\n      },\n      {\n        \"id\": \"N2\",\n        \"type\": \"router\",\n        \"label\": \"HQ 边界路由器 B (HRP)\",\n        \"zone\": \"Z1\"\n      },\n      {\n        \"id\": \"N3\",\n        \"type\": \"firewall\",\n        \"label\": \"双机防火墙集群\\\\n(南北向、IPS ON)\",\n        \"zone\": \"Z1\"\n      },\n      {\n        \"id\": \"N4\",\n        \"type\": \"switch\",\n        \"label\": \"核心交换\\\\n(MLAG)\",\n        \"zone\": \"Z1\"\n      },\n      {\n        \"id\": \"N5\",\n        \"type\": \"server\",\n        \"label\": \"SD-WAN 控制器 (on-prem)\\n+ 管理平面\",\n        \"zone\": \"Z1\"\n      },\n      {\n        \"id\": \"N6\",\n        \"type\": \"router\",\n        \"label\": \"门店 CPE 上海 (双上行)\",\n        \"zone\": \"Z2\"\n      },\n      {\n        \"id\": \"N7\",\n        \"type\": \"user\",\n        \"label\": \"POS/扫码枪终端 (终端 TLS 1.2)\",\n        \"zone\": \"Z2\"\n      },\n      {\n        \"id\": \"N8\",\n        \"type\": \"router\",\n        \"label\": \"深圳 CPE 实验室\",\n        \"zone\": \"Z3\"\n      },\n      {\n        \"id\": \"N9\",\n        \"type\": \"cloud_service\",\n        \"label\": \"企业云 VPC 网关/ VPN Hub\\\\n(汇聚 IPsec, BGP over tunnel)\",\n        \"zone\": \"Z4\"\n      }\n    ],\n    \"node_label_format\": \"双行，上面角色下面协议/AS，mono 10pt\"\n  },\n  \"connections\": {\n    \"items\": [\n      {\n        \"from\": \"N1\",\n        \"to\": \"N3\",\n        \"type\": \"physical\",\n        \"label\": \"10Gbps 内网·静态路由\"\n      },\n      {\n        \"from\": \"N2\",\n        \"to\": \"N3\",\n        \"type\": \"physical\",\n        \"label\": \"10Gbps 内网·静态路由\"\n      },\n      {\n        \"from\": \"N3\",\n        \"to\": \"N4\",\n        \"type\": \"physical\",\n        \"label\": \"L3 到核心\"\n      },\n      {\n        \"from\": \"N1\",\n        \"to\": \"N6\",\n        \"type\": \"encrypted\",\n        \"label\": \"MPLS L3VPN 标签交换 + SD-WAN overlay\"\n      },\n      {\n        \"from\": \"N1\",\n        \"to\": \"N6\",\n        \"type\": \"redundant\",\n        \"label\": \"Internet DTLS 备链路 300Mbps\"\n      },\n      {\n        \"from\": \"N2\",\n        \"to\": \"N8\",\n        \"type\": \"encrypted\",\n        \"label\": \"MPLS + 互联网混合选路\"\n      },\n      {\n        \"from\": \"N5\",\n        \"to\": \"N6\",\n        \"type\": \"logical\",\n        \"label\": \"控制/策略下发 Netconf/HTTPS\"\n      },\n      {\n        \"from\": \"N5\",\n        \"to\": \"N8\",\n        \"type\": \"logical\",\n        \"label\": \"控制/策略下发\"\n      },\n      {\n        \"from\": \"N4\",\n        \"to\": \"N9\",\n        \"type\": \"encrypted\",\n        \"label\": \"IPsec 隧道 + eBGP 65001-65555\"\n      },\n      {\n        \"from\": \"N7\",\n        \"to\": \"N6\",\n        \"type\": \"physical\",\n        \"label\": \"门店 LAN 1G\"\n      },\n      {\n        \"from\": \"N6\",\n        \"to\": \"N4\",\n        \"type\": \"encrypted\",\n        \"label\": \"业务回总部 DC 的优选路径\"\n      }\n    ],\n    \"line_style\": {\n      \"physical\": \"solid 2px slate #94A3B8\",\n      \"logical\": \"dashed 1.5px slate #64748B\",\n      \"redundant\": \"双 violet 平行线 表示双上行\",\n      \"encrypted\": \"emerald 2px + 锁 glyph 表示国密/ IPSec 可选注记\"\n    }\n  },\n  \"annotations\": {\n    \"ip_cidr_labels\": {\n      \"enabled\": true,\n      \"rule\": \"Z1~Z4 显式写 CIDR；隧道端点可写公网/33 位\"\n    },\n    \"az_labels\": {\n      \"enabled\": false,\n      \"rule\": \"非云多 AZ 场景，关闭 AZ 标，可改标 city code\"\n    }\n  },\n  \"legend\": {\n    \"enabled\": true,\n    \"position\": \"bottom-right\",\n    \"content\": \"router/防火墙/CPE/server glyph；MPLS 与互联网双上行样式；IPsec+BGP 上云；logical 为灰虚线\",\n    \"style\": \"small panel, mono 10pt\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"站点用虚线大框+ CIDR\",\n      \"MPLS 与 internet 以不同线型/平行双线区分\",\n      \"加密跨域链路带锁或 'IPsec' 小字\"\n    ],\n    \"avoid\": [\n      \"Cisco/华为 官方产品剪影\",\n      \"未标注速率的广域网粗线\"\n    ]\n  }\n}\n",
