        "categoryAccent": "#0A6E96",
        "templateRef": "technical-diagrams/sequence-diagram.md",
        "templateLabel": "Sequence Diagram",
        "promptHint": "浏览器端机密公开场景下的标准四角色握手，从 `/authorize` 到 `code` 换 `access_token` 再带 `Bearer` 调业务 API，是内部 IdP 迁移说明里引用频率最高的一段时序。",
        "promptContent": "{\n  \"type\": \"工程感时序图（UML sequence diagram）\",\n  \"goal\": \"生成一张 OAuth 2.0 授权码 + PKCE 时序位图，用于安全评审与移动/Web 公钥客户对接说明，消息编号完整、sync/return 风格区分\",\n  \"canvas\": {\n    \"aspect_ratio\": \"16:9\",\n    \"background\": \"deep slate #0F172A with subtle 1px grid #1E293B at 32px spacing\",\n    \"outer_padding\": \"60px\"\n  },\n  \"title_strip\": {\n    \"title\": \"OAuth 2.0 Authorization Code + PKCE\",\n    \"subtitle\": \"Keycloak 24 · SPA @ app.nimbus.id\",\n    \"position\": \"top-left, JetBrains Mono / SF Mono, light gray\"\n  },\n  \"actors\": {\n    \"count\": 4,\n    \"items\": [\n      {\n        \"id\": \"A1\",\n        \"name\": \"User\",\n        \"type\": \"user\",\n        \"icon_glyph\": \"stick figure outline\"\n      },\n      {\n        \"id\": \"A2\",\n        \"name\": \"Web SPA (React)\",\n        \"type\": \"client\",\n        \"icon_glyph\": \"browser window outline\"\n      },\n      {\n        \"id\": \"A3\",\n        \"name\": \"Keycloak (realm=nimbus)\",\n        \"type\": \"service\",\n        \"icon_glyph\": \"shield outline\"\n      },\n      {\n        \"id\": \"A4\",\n        \"name\": \"BFF (FastAPI + RS256)\",\n        \"type\": \"service\",\n        \"icon_glyph\": \"database / server outline\"\n      }\n    ],\n    \"header_box_style\": {\n      \"shape\": \"rounded rectangle, corner radius 6px\",\n      \"fill\": \"type-coded color × 12% opacity\",\n      \"border\": \"1.5px solid type-coded color\",\n      \"size\": \"160px wide × 64px tall, all headers identical size, evenly spaced\",\n      \"label\": \"actor name in mono 11pt + small icon glyph above name\"\n    },\n    \"type_color_map\": {\n      \"user\": \"cyan #22D3EE\",\n      \"client\": \"blue #60A5FA\",\n      \"service\": \"emerald #34D399\",\n      \"database\": \"violet #A78BFA\",\n      \"external\": \"slate #94A3B8\"\n    }\n  },\n  \"lifelines\": {\n    \"rule\": \"每个 actor header 下方画一条垂直虚线 (1px dashed slate #475569)，从 header 底部一直延伸到画布底部\",\n    \"spacing\": \"lifelines 之间等距，间距 ≥ 200px\"\n  },\n  \"messages\": {\n    \"count\": 10,\n    \"items\": [\n      {\n        \"id\": \"M1\",\n        \"from\": \"A1\",\n        \"to\": \"A2\",\n        \"label\": \"1. 点击「使用企业账户登录」\",\n        \"type\": \"sync\"\n      },\n      {\n        \"id\": \"M2\",\n        \"from\": \"A2\",\n        \"to\": \"A2\",\n        \"label\": \"2. 生成 code_verifier，推导 code_challenge=S256(verifier)\",\n        \"type\": \"self\"\n      },\n      {\n        \"id\": \"M3\",\n        \"from\": \"A2\",\n        \"to\": \"A3\",\n        \"label\": \"3. GET /realms/nimbus/protocol/openid-connect/auth?client_id=portal-spa&response_type=code&code_challenge=...&code_challenge_method=S256&redirect_uri=https://app.nimbus.id/cb\",\n        \"type\": \"sync\"\n      },\n      {\n        \"id\": \"M4\",\n        \"from\": \"A3\",\n        \"to\": \"A1\",\n        \"label\": \"4. 302 → 展示登录/ MFA 页\",\n        \"type\": \"return\"\n      },\n      {\n        \"id\": \"M5\",\n        \"from\": \"A1\",\n        \"to\": \"A3\",\n        \"label\": \"5. 提交 username + password + TOTP\",\n        \"type\": \"sync\"\n      },\n      {\n        \"id\": \"M6\",\n        \"from\": \"A3\",\n        \"to\": \"A2\",\n        \"label\": \"6. 302 redirect_uri?code=...&state=anti_csrf\",\n        \"type\": \"return\"\n      },\n      {\n        \"id\": \"M7\",\n        \"from\": \"A2\",\n        \"to\": \"A3\",\n        \"label\": \"7. POST /token (grant_type=authorization_code&code&redirect_uri&client_id&code_verifier)\",\n        \"type\": \"sync\"\n      },\n      {\n        \"id\": \"M8\",\n        \"from\": \"A3\",\n        \"to\": \"A2\",\n        \"label\": \"8. 200 { access_token, id_token, refresh_token, token_type: Bearer, expires_in }\",\n        \"type\": \"return\"\n      },\n      {\n        \"id\": \"M9\",\n        \"from\": \"A2\",\n        \"to\": \"A4\",\n        \"label\": \"9. GET /v1/tenants (Authorization: Bearer access_token, traceparent)\",\n        \"type\": \"sync\"\n      },\n      {\n        \"id\": \"M10\",\n        \"from\": \"A4\",\n        \"to\": \"A2\",\n        \"label\": \"10. 200 { tenant_id, entitlements[] }，aud 匹配 portal-spa\",\n        \"type\": \"return\"\n      }\n    ],\n    \"message_style\": {\n      \"sync\": \"solid line 1.5px slate #94A3B8, filled triangle arrowhead at target\",\n      \"async\": \"solid line 1.5px slate #94A3B8, hollow triangle arrowhead\",\n      \"return\": \"dashed line 1.5px slate #64748B, hollow triangle arrowhead\",\n      \"self\": \"horizontal arrow that loops out to the right and back to the same lifeline (bracket shape)\"\n    },\n    \"label_format\": \"<编号>. <消息内容>，mono 10pt，标在 arrow 上方居中\"\n  },\n  \"activation_bars\": {\n    \"enabled\": true,\n    \"rule\": \"在 actor lifeline 上画细长矩形（4-6px 宽）覆盖该 actor 处理消息的时间段；颜色用 actor 的 type color，半透明\",\n    \"vertical_extent\": \"从该 actor 收到一个 message 开始，到它发出 return 结束\"\n  },\n  \"annotations\": {\n    \"notes\": {\n      \"enabled\": true,\n      \"rule\": \"在 M3 旁附便签：PKCE 防止 code 被截获后换 token；state 与 OIDC nonce 需校验\"\n    },\n    \"loops_alts\": {\n      \"enabled\": false,\n      \"rule\": \"如失败分支可用 alt 框，本次仅主路径\"\n    }\n  },\n  \"legend\": {\n    \"enabled\": true,\n    \"position\": \"bottom-right\",\n    \"content\": \"actor type → color, message style → meaning (sync solid / return dashed / self bracket)\",\n    \"style\": \"small panel, semi-transparent bg, mono 10pt\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"actor headers 等大小、等间距、水平对齐\",\n      \"lifelines 垂直、等间距\",\n      \"messages 严格按时间从上到下\",\n      \"每条 message 有编号 + 简洁标签\",\n      \"sync / return 用不同箭头风格\",\n      \"暗色 grid + 等宽字体\",\n      \"legend 必画\"\n    ],\n    \"avoid\": [\n      \"return 用实线箭头\",\n      \"用 emoji 当 actor 图标\",\n      \"声称可编辑 SVG\"\n    ]\n  }\n}\n",
