        "promptContent": "{\n  \"type\": \"工程感状态机 / 生命周期图（UML state diagram）\",\n  \"goal\": \"生成一张 B2C 主单从 CREATED 到各终态的 UML 状态位图，终态用靶心、过渡边标事件与 guard，自循环只用于支付重试\",\n  \"canvas\": {\n    \"aspect_ratio\": \"16:9\",\n    \"background\": \"deep slate #0F172A with subtle 1px grid #1E293B at 32px spacing\",\n    \"outer_padding\": \"60px\"\n  },\n  \"title_strip\": {\n    \"title\": \"Nimbus OMS · Order 状态机\",\n    \"subtitle\": \"CREATED → PAID → FULFILLING → SHIPPED → DELIVERED / REFUNDED / CANCELLED\",\n    \"position\": \"top-left, JetBrains Mono / SF Mono, light gray\"\n  },\n  \"states\": {\n    \"count\": 9,\n    \"items\": [\n      {\n        \"id\": \"S0\",\n        \"type\": \"initial\",\n        \"label\": \"\"\n      },\n      {\n        \"id\": \"S1\",\n        \"type\": \"state\",\n        \"label\": \"CREATED\",\n        \"category\": \"active\"\n      },\n      {\n        \"id\": \"S2\",\n        \"type\": \"state\",\n        \"label\": \"PAID\",\n        \"category\": \"active\"\n      },\n      {\n        \"id\": \"S3\",\n        \"type\": \"state\",\n        \"label\": \"FULFILLING\",\n        \"category\": \"waiting\"\n      },\n      {\n        \"id\": \"S4\",\n        \"type\": \"state\",\n        \"label\": \"SHIPPED\",\n        \"category\": \"active\"\n      },\n      {\n        \"id\": \"S5\",\n        \"type\": \"state\",\n        \"label\": \"DELIVERED\",\n        \"category\": \"success_terminal\"\n      },\n      {\n        \"id\": \"S6\",\n        \"type\": \"state\",\n        \"label\": \"REFUNDED\",\n        \"category\": \"fail_terminal\"\n      },\n      {\n        \"id\": \"S7\",\n        \"type\": \"state\",\n        \"label\": \"CANCELLED\",\n        \"category\": \"fail_terminal\"\n      },\n      {\n        \"id\": \"ST\",\n        \"type\": \"final\",\n        \"label\": \"\"\n      }\n    ]\n  },\n  \"state_style\": {\n    \"initial\": {\n      \"shape\": \"filled solid circle, ~16px diameter\",\n      \"color\": \"cyan #22D3EE solid\"\n    },\n    \"final\": {\n      \"shape\": \"concentric double circle (bullseye), outer ~18px, inner solid 10px\",\n      \"color\": \"rose #FB7185\"\n    },\n    \"state\": {\n      \"shape\": \"rounded rectangle, corner radius 12px, 160×72px typical\",\n      \"fill\": \"category color × 12% opacity\",\n      \"border\": \"1.5px solid in category color\",\n      \"label\": \"state name in mono 12pt, centered, light text on dark fill\",\n      \"optional_internal_label\": \"可在大状态内部底部加 'entry: persist_status'\"\n    }\n  },\n  \"category_color_map\": {\n    \"active\": \"emerald #34D399\",\n    \"waiting\": \"amber #FBBF24\",\n    \"success_terminal\": \"blue #60A5FA\",\n    \"fail_terminal\": \"rose #FB7185\",\n    \"error\": \"rose #FB7185\",\n    \"neutral\": \"slate #94A3B8\"\n  },\n  \"transitions\": {\n    \"items\": [\n      {\n        \"from\": \"S0\",\n        \"to\": \"S1\",\n        \"label\": \"place_order / emit order.created\"\n      },\n      {\n        \"from\": \"S1\",\n        \"to\": \"S1\",\n        \"label\": \"pay_retry\",\n        \"self_loop\": true\n      },\n      {\n        \"from\": \"S1\",\n        \"to\": \"S2\",\n        \"label\": \"pay_success [channel=wechat|alipay] / capture_txn\"\n      },\n      {\n        \"from\": \"S1\",\n        \"to\": \"S7\",\n        \"label\": \"close_timeout [now > payment_deadline] / release_hold\"\n      },\n      {\n        \"from\": \"S1\",\n        \"to\": \"S7\",\n        \"label\": \"cancel [buyer] / unstock\"\n      },\n      {\n        \"from\": \"S2\",\n        \"to\": \"S3\",\n        \"label\": \"allocate [inventory_ok] / create_wave\"\n      },\n      {\n        \"from\": \"S2\",\n        \"to\": \"S6\",\n        \"label\": \"refund_full_approved [ops] / reverse_payment\"\n      },\n      {\n        \"from\": \"S3\",\n        \"to\": \"S4\",\n        \"label\": \"handover_carrier [运单已获取] / write tracking_no\"\n      },\n      {\n        \"from\": \"S3\",\n        \"to\": \"S6\",\n        \"label\": \"refund_before_ship [风控] / cancel_pick\"\n      },\n      {\n        \"from\": \"S4\",\n        \"to\": \"S5\",\n        \"label\": \"confirm_receipt [buyer] / close_settle\"\n      },\n      {\n        \"from\": \"S4\",\n        \"to\": \"S6\",\n        \"label\": \"return_to_sender [7d 无签收] / partial_refund\"\n      },\n      {\n        \"from\": \"S5\",\n        \"to\": \"ST\",\n        \"label\": \"\"\n      },\n      {\n        \"from\": \"S6\",\n        \"to\": \"ST\",\n        \"label\": \"\"\n      },\n      {\n        \"from\": \"S7\",\n        \"to\": \"ST\",\n        \"label\": \"\"\n      }\n    ],\n    \"transition_style\": {\n      \"default\": \"thin solid arrow 1.5px slate #94A3B8 with filled triangle arrowhead\",\n      \"self_loop\": \"small loop curving above the state, returning to itself\",\n      \"label_format\": \"<event> [guard] / <action>，mono 9-10pt 标在边的中间，背景与 canvas 融合避免重叠\"\n    },\n    \"rule_routing\": \"尽量正交或 ≤ 30° 斜线，避免边穿过节点\"\n  },\n  \"composite_states\": {\n    \"enabled\": false,\n    \"rule\": \"if true, can group sub-states inside a larger rounded rectangle\"\n  },\n  \"legend\": {\n    \"enabled\": true,\n    \"position\": \"bottom-right\",\n    \"content\": \"category color → 进行中 / 等待 / 成功终态 / 失败终态；initial / final 形状；self-loop 为 pay_retry\",\n    \"style\": \"small panel, semi-transparent bg, mono 10pt\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"initial 是实心圆 / final 是靶心\",\n      \"transitions 含 event [guard] / action 格式\",\n      \"自循环为 loop 形\",\n      \"legend 必画\"\n    ],\n    \"avoid\": [\n      \"用菱形当 state\",\n      \"终态画成普通矩形\",\n      \"声称可编辑 xstate 源\"\n    ]\n  }\n}\n",
