        "promptContent": "{\n  \"type\": \"工程感状态机 / 生命周期图（UML state diagram）\",\n  \"goal\": \"生成一张文章实体 `Article` 在 CMS 与机审/人审服务之间的状态机位图，终态与违规分支清晰，可贴在内容安全 SOP 附录\",\n  \"canvas\": {\n    \"aspect_ratio\": \"4:3\",\n    \"background\": \"deep slate #0F172A with subtle 1px grid #1E293B at 32px spacing\",\n    \"outer_padding\": \"60px\"\n  },\n  \"title_strip\": {\n    \"title\": \"Aurora CMS · article.status 状态机\",\n    \"subtitle\": \"DRAFT → REVIEW → PUBLISHED / REJECTED / TAKEN_DOWN / DELETED\",\n    \"position\": \"top-left, JetBrains Mono / SF Mono, light gray\"\n  },\n  \"states\": {\n    \"count\": 10,\n    \"items\": [\n      {\n        \"id\": \"S0\",\n        \"type\": \"initial\",\n        \"label\": \"\"\n      },\n      {\n        \"id\": \"S1\",\n        \"type\": \"state\",\n        \"label\": \"DRAFT\",\n        \"category\": \"active\"\n      },\n      {\n        \"id\": \"S2\",\n        \"type\": \"state\",\n        \"label\": \"PENDING_REVIEW\",\n        \"category\": \"waiting\"\n      },\n      {\n        \"id\": \"S3\",\n        \"type\": \"state\",\n        \"label\": \"HUMAN_REVIEW\",\n        \"category\": \"waiting\"\n      },\n      {\n        \"id\": \"S4\",\n        \"type\": \"state\",\n        \"label\": \"PUBLISHED\",\n        \"category\": \"active\"\n      },\n      {\n        \"id\": \"S5\",\n        \"type\": \"state\",\n        \"label\": \"REJECTED\",\n        \"category\": \"fail_terminal\"\n      },\n      {\n        \"id\": \"S6\",\n        \"type\": \"state\",\n        \"label\": \"TAKEN_DOWN\",\n        \"category\": \"fail_terminal\"\n      },\n      {\n        \"id\": \"S7\",\n        \"type\": \"state\",\n        \"label\": \"UNLISTED\",\n        \"category\": \"waiting\"\n      },\n      {\n        \"id\": \"S8\",\n        \"type\": \"state\",\n        \"label\": \"DELETED\",\n        \"category\": \"fail_terminal\"\n      },\n      {\n        \"id\": \"ST\",\n        \"type\": \"final\",\n        \"label\": \"\"\n      }\n    ]\n  },\n  \"state_style\": {\n    \"initial\": {\n      \"shape\": \"filled solid circle, ~16px\",\n      \"color\": \"cyan #22D3EE\"\n    },\n    \"final\": {\n      \"shape\": \"concentric double circle\",\n      \"color\": \"rose #FB7185\"\n    },\n    \"state\": {\n      \"shape\": \"rounded rectangle, corner radius 12px\",\n      \"fill\": \"category color × 12% opacity\",\n      \"border\": \"1.5px solid in category color\",\n      \"label\": \"mono 12pt\"\n    }\n  },\n  \"category_color_map\": {\n    \"active\": \"emerald #34D399\",\n    \"waiting\": \"amber #FBBF24\",\n    \"success_terminal\": \"blue #60A5FA\",\n    \"fail_terminal\": \"rose #FB7185\"\n  },\n  \"transitions\": {\n    \"items\": [\n      {\n        \"from\": \"S0\",\n        \"to\": \"S1\",\n        \"label\": \"init_draft\"\n      },\n      {\n        \"from\": \"S1\",\n        \"to\": \"S2\",\n        \"label\": \"submit [author=owner] / enqueue ml_review\"\n      },\n      {\n        \"from\": \"S2\",\n        \"to\": \"S3\",\n        \"label\": \"ml_flagged [score>0.62] / assign reviewer\"\n      },\n      {\n        \"from\": \"S2\",\n        \"to\": \"S4\",\n        \"label\": \"ml_clear [score<0.35] / publish_direct\"\n      },\n      {\n        \"from\": \"S3\",\n        \"to\": \"S4\",\n        \"label\": \"approve [role=content_editor] / set published_at\"\n      },\n      {\n        \"from\": \"S3\",\n        \"to\": \"S5\",\n        \"label\": \"reject [reason_code] / notify 微信 公众号模板消息\"\n      },\n      {\n        \"from\": \"S4\",\n        \"to\": \"S6\",\n        \"label\": \"report_spam [count>阈值] / hide_cdn\"\n      },\n      {\n        \"from\": \"S4\",\n        \"to\": \"S7\",\n        \"label\": \"unlist [compliance=voluntary] / 403 public\"\n      },\n      {\n        \"from\": \"S6\",\n        \"to\": \"S4\",\n        \"label\": \"reinstate [appeal=accepted] / rebuild index\"\n      },\n      {\n        \"from\": \"S4\",\n        \"to\": \"S8\",\n        \"label\": \"soft_delete [admin] / tombstone\"\n      },\n      {\n        \"from\": \"S7\",\n        \"to\": \"S4\",\n        \"label\": \"relist [ops] / restore slug\"\n      },\n      {\n        \"from\": \"S5\",\n        \"to\": \"ST\",\n        \"label\": \"\"\n      },\n      {\n        \"from\": \"S6\",\n        \"to\": \"ST\",\n        \"label\": \"\"\n      },\n      {\n        \"from\": \"S8\",\n        \"to\": \"ST\",\n        \"label\": \"\"\n      }\n    ],\n    \"transition_style\": {\n      \"default\": \"solid arrow with label\",\n      \"self_loop\": \"loop only if used\",\n      \"label_format\": \"event [guard] / action\"\n    },\n    \"rule_routing\": \"正交 / 小角度斜线，避免压字\"\n  },\n  \"composite_states\": {\n    \"enabled\": true,\n    \"rule\": \"可选：将 PENDING_REVIEW 与 HUMAN_REVIEW 包在 composite 'Moderation' 大框，标注 entry=assign_job_id\"\n  },\n  \"legend\": {\n    \"enabled\": true,\n    \"position\": \"bottom-right\",\n    \"content\": \"终态 / 人审 / 机审 颜色与形状约定；DELETED 为软删终态\",\n    \"style\": \"small panel, mono 10pt\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"initial / final 形状正确\",\n      \"transition 全带 label\",\n      \"legend 必画\"\n    ],\n    \"avoid\": [\n      \"用流程图形状代替 state\",\n      \"微信 字样与业务字段在图中拼写错误\"\n    ]\n  }\n}\n",
