        "categoryAccent": "#4F4F4F",
        "templateRef": "typography-and-text-layout/bilingual-layout-visual.md",
        "templateLabel": "Bilingual Layout Visual",
        "promptHint": "中文主标题最大，英文为气质副行，下附展期与场馆，主视觉在右下为抽象山水几何切割，朱砂红＋古纸色，美术馆投放通用。",
        "promptContent": "{\n  \"type\": \"中英对照文化海报\",\n  \"goal\": \"生成 3:4 竖版文化展览主视觉，可用于主海报、请柬、线上首图，双语不是简单机翻要语气体面\",\n  \"languages\": {\n    \"primary\": \"中文\",\n    \"secondary\": \"英文\"\n  },\n  \"title_block\": {\n    \"main_zh\": \"照见之间\",\n    \"main_en\": \"BETWEEN THE TWO HANDS\",\n    \"subtitle_zh\": \"当代东方与西方工艺互鉴年展\",\n    \"subtitle_en\": \"A Contemporary Survey of East-West Craft\",\n    \"alignment\": \"左上与左中分块左对齐，主标题在竖向黄金分割偏上，英文副行宽度不超过中文标题宽\",\n    \"hierarchy_rule\": \"中文主标题 > 英文主行 > 中文副题 > 英文副题 > 元信息行\"\n  },\n  \"meta\": {\n    \"date\": \"2026.5.1 - 2026.6.15\",\n    \"venue\": \"西岸美术馆 · 上海\",\n    \"presenter\": \"X MUSEUM ALLIANCE 联合策展\"\n  },\n  \"main_visual\": {\n    \"description\": \"右下 45% 区域为低多边形山水剪影与直尺圆规线条叠压，不模仿任何单一艺术家 signature，用朱砂色块、墨线、留白呼吸\",\n    \"position\": \"右下大区，上缘与主标题中轴大致齐平、不穿过标题字\"\n  },\n  \"design\": {\n    \"primary_color\": \"#9B2B2A 朱砂\",\n    \"background_color\": \"#F0E6D4 古纸\",\n    \"zh_font\": \"现代宋体，标题用字重 700，正文 400\",\n    \"en_font\": \"Cormorant Garamond 或等气质 modern serif 仅用于主副英文行，元信息可换为 Source Serif 4 小号\",\n    \"grid\": \"12 栏栅格，主标题站 1-6 栏，主视觉 7-12 栏，终稿不显示格线\"\n  },\n  \"aspect_ratio\": \"3:4\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"中文字体与拉丁字体形态明显不同源，不共用同一文件混排\",\n      \"英译在语义上与中文展览名呼应而不是硬译每个字\",\n      \"留白不低于画面 20%\",\n      \"色数 ≤3 大面积色\"\n    ],\n    \"avoid\": [\n      \"中文标题用西文无衬线直接充当\",\n      \"英副题字号接近中文主题\",\n      \"在角落堆二维码与六个赞助 logo（如需要可另做物料）\"\n    ]\n  }\n}\n",
