        "promptContent": "{\n  \"type\": \"中日对照设计\",\n  \"goal\": \"生成 2:3 或 3:4 一屏的跨文化茶主题海报，气质偏日式雑志封面但中文读者友好，不山寨具体期刊封型\",\n  \"languages\": {\n    \"primary\": \"日文\",\n    \"secondary\": \"中文\"\n  },\n  \"title_block\": {\n    \"main_zh\": \"一叶渡海\",\n    \"main_en\": \"海を越える一葉\",\n    \"subtitle_zh\": \"静冈与福鼎：茶与器的双城记\",\n    \"subtitle_en\": \"静岡焼と福鼎白茶の対话\",\n    \"alignment\": \"右上竖排大标题、左中横排中文、左下赞助与展期小字，栅格 10 栏\",\n    \"hierarchy_rule\": \"日文主标题行 > 中文副名行 > 日文副行 > 展期等元信息\"\n  },\n  \"meta\": {\n    \"date\": \"2026.7.1 - 2026.7.20\",\n    \"venue\": \"杭州 · 之江文化艺术中心\",\n    \"presenter\": \"东亚民艺振兴会 · 之江文投\"\n  },\n  \"main_visual\": {\n    \"description\": \"左下 40% 为一只开片青瓷茶碗的俯拍＋单枚茶叶在碗缘将落未落，背景为和纸肌理的浅靛平涂，不画真实商标在碗上\",\n    \"position\": \"左下，给右上日文竖排与顶边 15% 呼吸\"\n  },\n  \"design\": {\n    \"primary_color\": \"#1E2A3A 深靛\",\n    \"background_color\": \"#E8E2D3 和纸\",\n    \"zh_font\": \"华文黑体或思源黑体 细到中等，用于中文副行与展讯\",\n    \"en_font\": \"日文字体使用ヒラギノ角ゴ或思源黑体日版、竖排时遵守标点禁则；拉丁仅用于年号等数字的独立半角行\",\n    \"grid\": \"8 栏纵分，竖排区占 2 栏宽\"\n  },\n  \"aspect_ratio\": \"2:3\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"日中文各自使用对应字形体系，不混为同一转曲文件\",\n      \"主视觉茶碗不贴商业品牌、可有抽象纹样\",\n      \"全页在三种主色内完成（靛、纸、若草点缀 ≤6% 面积在叶脉）\"\n    ],\n    \"avoid\": [\n      \"用中文宋体排日文\",\n      \"竖排与横排行距过密成「豆腐块」\",\n      \"在一张上再加英文明细块\"\n    ]\n  }\n}\n",
