        "promptHint": "朱红＋米黄＋半色调网点，主标四字占幅超半，下缘英文与主办方小字，适合地铁灯箱与通栏下刊。",
        "promptContent": "{\n  \"type\": \"日式高能量大字海报\",\n  \"goal\": \"生成以中文主标语为绝对主体的竖版活动海报，气质接近日本昭和末平成初促销页但用中文，装饰几何极少、可读性第一\",\n  \"headline\": {\n    \"text\": \"一起跑过\",\n    \"language\": \"中文主标，英文与数字为辅\",\n    \"size\": \"占画面高度约 58%\",\n    \"alignment\": \"水平居中、略靠上，字底对齐一条隐形的黄金分割横线\",\n    \"treatment\": \"粗黑体轮廓外再叠半阶红色错位、局部叠砂目网点与 20% 透明噪点，白芯黑边增强远距可读\"\n  },\n  \"subheadline\": {\n    \"text\": \"CITY RUN FOR CARE 2026\",\n    \"size\": \"主标字高的四分之一宽\",\n    \"position\": \"主标下缘 6% 处居中小写无衬线全大写\"\n  },\n  \"small_text\": {\n    \"items\": [\n      \"4.28 - 5.4 城滨绿道封闭路段晨跑与家庭跑\",\n      \"联合主办：城滨市体育局 · 心桥公益基金会\"\n    ],\n    \"position\": \"底左右两角，左为日期行右为联办行，不超出安全裁切 8mm 内\"\n  },\n  \"design\": {\n    \"primary_color\": \"#C41E2E 朝朱\",\n    \"background_color\": \"#F2EBD4 和纸米黄\",\n    \"decoration\": \"四个小圆、两个短粗箭头、一条斜 30° 的细线分割块面，不交叉主笔划\",\n    \"typography_family\": \"中文：现代极粗黑；英文：窄体几何无衬线；仅两家族三以内字重\"\n  },\n  \"aspect_ratio\": \"3:4 印刷，出血各 3mm 外不排关键小字\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"主标语在街对面扫一眼可辨\",\n      \"主色面块不超过三种（朱、米、黑线）\",\n      \"装饰物 ≤5 个且透明度低于 40% 不压字\",\n      \"全篇无错字、数字与年号自洽\"\n    ],\n    \"avoid\": [\n      \"主字小于画高 40%\",\n      \"为炫技加入第四种大面积色\",\n      \"网点密到发灰发脏\",\n      \"英文副标大过中文主标\"\n    ]\n  }\n}\n",
