        "promptContent": "{\n  \"type\": \"极简瑞士排版大字海报\",\n  \"goal\": \"生成果壳极简、以栅格与字号层级为唯一趣味的 2:3 或 1:1 可裁海报，无插画无照片，无渐变\",\n  \"headline\": {\n    \"text\": \"秩序即善意\",\n    \"language\": \"中文\",\n    \"size\": \"占画面高 40%，宽 70%\",\n    \"alignment\": \"按 12 栏栅格左对齐，左缘距 1/12 空栏\",\n    \"treatment\": \"无衬线统一字重 700、字距 -2%、无描边、无噪点、无半色调\"\n  },\n  \"subheadline\": {\n    \"text\": \"OPEN TALK · 2026.01.18 · SHANGHAI\",\n    \"size\": \"主标字高 0.2\",\n    \"position\": \"主标下 12mm（按比例换算）同左对齐，全大写与数字混排，细线 1pt 在英文词间\"\n  },\n  \"small_text\": {\n    \"items\": [\n      \"主办：和川建筑工作室\",\n      \"对谈：Jensen Huang 影像致辞 · 线下嘉宾含本地规划学者两名（此处为排印示意不列真实姓名）\"\n    ],\n    \"position\": \"画面右下与左下：左下主办，右下对谈，均 8pt 等效英文细体高度\"\n  },\n  \"design\": {\n    \"primary_color\": \"纯黑 #000000\",\n    \"background_color\": \"纯白 #FFFFFF\",\n    \"decoration\": \"距底边 18% 处一条自左 1/3 到右 2/3 的 0.5pt 水平线，不得与其他文字接触\",\n    \"typography_family\": \"中文：新 grotesk 无衬线；英文：同一家族拉丁部分；禁止书法体\"\n  },\n  \"aspect_ratio\": \"1:1 可扩展至 2:3，扩展时只增加上下白不拉字\",\n  \"constraints\": {\n    \"must_keep\": [\n      \"字面仍占绝对主体但留白克制有呼吸，不像 Word 居中大字\",\n      \"全图仅黑白两色，无灰阶大面积（允许文字抗锯齿的屏幕灰）\",\n      \"装饰只有一条线 + 小字，不加 logo 色块\"\n    ],\n    \"avoid\": [\n      \"出现第三种颜色\",\n      \"为填充空白加入几何噪点\",\n      \"标题超过七个字本例已用四字若改稿勿超过八字\"\n    ]\n  }\n}\n",
