        "promptContent": "{\n  \"type\": \"移动端双人聊天截图样机\",\n  \"goal\": \"生成一张高仿真的微信双人聊天截图，画面像两位虚构科技 CEO 之间的真实深夜对话，整体像真实截图而非合成图\",\n  \"platform\": {\n    \"name\": \"微信\",\n    \"color_mode\": \"light\",\n    \"language\": \"中文 + 少量英文穿插（科技圈高管语风）\"\n  },\n  \"header\": {\n    \"status_bar\": \"顶部状态栏，时间 '23:47'，运营商 'AT&T'，5G、Wi-Fi 满格、电量 41%（特意低电量，体现深夜对话）\",\n    \"navigation\": {\n      \"back\": \"左上返回箭头 + 蓝色 '消息(3)'\",\n      \"contact_avatar\": \"对话方头像：一位 40 岁出头的虚构男性科技 CEO，圆脸正面照、灰色 T 恤、浅色背景、表情略僵硬的微笑（不指向任何具体真实公众人物）\",\n      \"contact_name\": \"Z\",\n      \"online_status\": \"（无在线状态，微信不显示）\",\n      \"right_actions\": [\n        \"右上三点菜单\"\n      ]\n    }\n  },\n  \"self_identity\": {\n    \"name\": \"M\",\n    \"note\": \"本机视角默认是另一位虚构的 50 多岁男性科技创始人（短棕发、棱角分明、常着黑色 T 恤），所以右侧绿色气泡来自本人\"\n  },\n  \"conversation\": {\n    \"self_alignment\": \"right\",\n    \"self_bubble_color\": \"微信经典浅绿色 #95EC69\",\n    \"other_alignment\": \"left\",\n    \"other_bubble_color\": \"白色 + 浅灰边框 #E5E7EB\",\n    \"message_count\": 10,\n    \"messages\": [\n      {\n        \"role\": \"self\",\n        \"type\": \"text\",\n        \"text\": \"Z，认真问一句：cage match 你来不来？我练柔术练了一年了 🥋\",\n        \"timestamp\": \"23:42\"\n      },\n      {\n        \"role\": \"other\",\n        \"type\": \"text\",\n        \"text\": \"Send location.\",\n        \"timestamp\": \"23:42\"\n      },\n      {\n        \"role\": \"self\",\n        \"type\": \"text\",\n        \"text\": \"拉斯维加斯八角笼，老地方\",\n        \"timestamp\": \"23:43\"\n      },\n      {\n        \"role\": \"self\",\n        \"type\": \"location\",\n        \"description\": \"微信定位卡片：'UFC Apex, Las Vegas, NV'，下面一行小字 '6650 El Camino Rd'，左侧有地图缩略图\",\n        \"timestamp\": \"23:43\"\n      },\n      {\n        \"role\": \"other\",\n        \"type\": \"voice\",\n        \"duration\": \"00:11\",\n        \"label\": \"语音条 + 已读小蓝点（Z 回了一段 11 秒语音，气泡下方一行小字 '语音转文字：日期我让 PR 团队对一下，但原则上同意。'）\",\n        \"timestamp\": \"23:44\"\n      },\n      {\n        \"role\": \"self\",\n        \"type\": \"image\",\n        \"description\": \"本人在一辆三角块状电动皮卡驾驶座里的自拍，戴黑色棒球帽，背景是航天厂区夜景，照片右下角微信图片角标\",\n        \"timestamp\": \"23:45\"\n      },\n      {\n        \"role\": \"self\",\n        \"type\": \"text\",\n        \"text\": \"刚开车路过厂区，给你打个招呼 😎\",\n        \"timestamp\": \"23:45\"\n      },\n      {\n        \"role\": \"other\",\n        \"type\": \"sticker\",\n        \"description\": \"微信收藏表情包：表情严肃的程序员举牌 'NOTED.'，黑白漫画风\",\n        \"timestamp\": \"23:46\"\n      },\n      {\n        \"role\": \"other\",\n        \"type\": \"text\",\n        \"text\": \"我建议改地点：Lake Tahoe 我家后院，规则用 IBJJF 标准，我录直播给我们家社交平台\",\n        \"timestamp\": \"23:46\"\n      },\n      {\n        \"role\": \"self\",\n        \"type\": \"text\",\n        \"text\": \"成交。我家社交平台直播一份，给我留主机位 🎤\",\n        \"timestamp\": \"23:47\"\n      }\n    ]\n  },\n  \"footer\": {\n    \"input_bar\": {\n      \"left_icons\": [\n        \"语音 mic 图标\"\n      ],\n      \"placeholder\": \"（输入框为空）\",\n      \"right_icons\": [\n        \"+ 笑脸表情\",\n        \"+ 加号\"\n      ]\n    },\n    \"home_indicator\": \"底部白色 home 指示条\"\n  },\n  \"style\": {\n    \"rendering\": \"高保真 iOS 微信浅色模式截图，9:19.5 纵向比例，整体像社交平台上流传的'内部聊天截图'\",\n    \"consistency\": \"气泡颜色、头像位置、时间戳样式、定位卡片、语音条、贴纸样式严格遵循微信官方风格\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"自己（绿色气泡，'M'）右对齐，'Z'（白色气泡）左对齐\",\n      \"顶部联系人名显示为 'Z'，头像是一位虚构 40 岁出头男性 CEO 的辨识度肖像\",\n      \"时间戳合理推进，23:42 → 23:47\",\n      \"中文清晰可读，没有错字；英文混入要符合科技圈高管说话风格\",\n      \"语音条带'语音转文字'小预览，符合微信新版功能\",\n      \"定位卡片样式严格按微信地图分享卡渲染\"\n    ],\n    \"avoid\": [\n      \"出现 iMessage 蓝色气泡或 Messenger 紫色气泡\",\n      \"气泡顺序错位、'M' 和 'Z' 头像/名字对调\",\n      \"时间戳倒退\",\n      \"脸部明显变形、双下巴诡异、瞳孔不对称等 AI artifact\",\n      \"刻意贴近任何具体真实公众人物的肖像细节\",\n      \"出现具体公司或社交平台 logo 作为水印（应是干净的微信截图）\"\n    ]\n  }\n}\n",
