        "promptContent": "{\n  \"type\": \"品牌创始人直播带货样机\",\n  \"goal\": \"生成一张明星个人 IP 跨界带货直播截图样机，整体像粉丝刚刚截下来的真实手机直播画面\",\n  \"subject\": {\n    \"source_mode\": \"anonymous-celebrity-style\",\n    \"description\": \"一位 30 岁左右的虚构金棕长卷发女歌手主体（鹅蛋脸、淡橄榄肤色、薄荷绿色针织衫、颈部佩戴小猫造型项链、妆容自然偏暖）的半身真人级肖像；不指向任何具体真实公众人物\",\n    \"pose\": \"略微侧身，双手轻轻捧着一只香水瓶，像在向镜头展示瓶身\",\n    \"expression\": \"微笑，眼神温柔看向镜头，像在跟粉丝聊天\"\n  },\n  \"scene\": {\n    \"background_style\": \"粉色与香槟金渐变的直播间布景，墙面挂着复古唱片与小吉他装饰\",\n    \"lighting\": \"柔和暖光顶灯 + 粉色补光，整体像 Vlog 灯光\",\n    \"extras\": \"桌面摆放干花、唱片、迷你蜡烛\"\n  },\n  \"product\": {\n    \"name\": \"Folklore 同名香水（限定首发）\",\n    \"category\": \"高端香氛\",\n    \"price\": \"¥ 1,288\",\n    \"selling_points\": [\n      \"森林木质调 + 香草尾香\",\n      \"全球限量 5,000 瓶\",\n      \"每瓶附亲笔签名卡片\"\n    ]\n  },\n  \"ui_overlay\": {\n    \"platform_style\": \"通用中文直播带货平台（接近小红书直播 / 淘宝直播混合风格）\",\n    \"top_header\": {\n      \"host_info\": \"圆形头像 + 名称 'Folklore 香氛官方'，副标题 '212.8万本场点赞'，红色 '+ 关注' 按钮\",\n      \"rank_badge\": \"金色 '全站第1名 · 美妆专场' 徽章\",\n      \"viewer_stats\": \"三位观众小头像 + '38.5w'、'27.1w'、'19.2w'，总在看 '156.8万'\"\n    },\n    \"mid_left_gifts\": {\n      \"count\": 3,\n      \"items\": [\n        \"头像 '深夜歌迷'，'送出 玫瑰花海'，玫瑰图标 × 1314\",\n        \"头像 'Folklore 林深'，'送出 嘉年华'，烟花图标 × 520\",\n        \"头像 '十三号星期五'，'送出 友谊手环'，手环图标 × 99\"\n      ]\n    },\n    \"bottom_left_chat\": {\n      \"system_message\": \"44 级勋章 '永远的歌迷俱乐部 加入了直播间'\",\n      \"message_count\": 7,\n      \"messages\": [\n        \"深夜歌迷: 终于等到这一刻 😭\",\n        \"Folklore_FAN: 这瓶香水我蹲了一整年！\",\n        \"深夜失眠: 想问问尾调持久度怎么样？\",\n        \"上海铁粉: 限量5000瓶能抢到吗 我手心出汗\",\n        \"13号星期五: 求问签名卡片是真的亲笔吗？\",\n        \"Lavender Haze: 主播今天好美 💛\",\n        \"下一站米兰: 海外歌迷报到！\"\n      ]\n    },\n    \"bottom_right_product_card\": {\n      \"hot_tag\": \"粉色 '限量首发 × 即将售罄'\",\n      \"image\": \"磨砂米色香水玻璃瓶，瓶身浮雕花藤与 'folklore' 字样\",\n      \"title\": \"Folklore 同名香水 50ml｜全球限定签名版\",\n      \"price\": \"¥ 1,288\",\n      \"button\": \"粉红色圆角 '抢' 按钮\",\n      \"floating_animation\": \"金色五角星 + 玫瑰花瓣沿右侧上飘\"\n    },\n    \"bottom_bar\": {\n      \"input_field\": \"'说点什么...'\",\n      \"icons\": [\n        \"笑脸\",\n        \"三个点\",\n        \"购物车（红点 8）\",\n        \"礼物盒\",\n        \"分享\"\n      ]\n    }\n  },\n  \"style\": {\n    \"visual_target\": \"粉丝实时截屏感的直播带货样机，温柔、暖、明星粉丝私域氛围\",\n    \"rendering\": \"真人写真级人像 + 直播平台叠加 UI + 暖色商业灯光\",\n    \"color_tone\": \"香槟金 + 玫瑰粉 + 直播红\"\n  },\n  \"constraints\": {\n    \"must_keep\": [\n      \"主体形象可识别且亲和力强\",\n      \"商品卡颜色与主播服装、背景协调\",\n      \"聊天区、礼物区、商品卡都必须出现\"\n    ],\n    \"avoid\": [\n      \"UI 中文出现错字\",\n      \"主体脸部畸形或缺乏神态\",\n      \"礼物图标与品牌调性不符（不要出现猎奇图标）\",\n      \"刻意贴近任何具体真实公众人物的肖像细节\"\n    ]\n  }\n}\n",
